export enum DocStatus {
  A_SUIVRE = "À suivre",
  CLASSE = "Classé"
}

export enum IncidentType {
  INCENDIE = "Incendie",
  DEGAT_EAUX = "Dégât des eaux",
  VANDALISME = "Vandalisme",
  ACCIDENT_TRAVAIL = "Accident de travail",
  PANNE_TECHNIQUE = "Panne technique",
  VOL_EFFRACTION = "Vol / Effraction",
  SINISTRE_ELECTRIQUE = "Sinistre électrique",
  AUTRE = "Autre"
}

export interface DocumentData {
  id: string;
  document_image: string; 
  mimeType: string;
  nature_incident: IncidentType;
  date_incident: string; // AAAA-MM-JJ
  heure_incident: string; // HH:mm
  lieu: string;
  objet: string;
  emetteur: string;
  reference_dossier: string;
  description_faits: string;
  dommages_constates: string;
  mesures_urgentes: string;
  rapport_technique: string; // Généré par IA (>300 mots)
  statut: DocStatus;
  created_at: number;
}

export type ScreenName = 'scanner' | 'dashboard' | 'stats' | 'settings';

export interface AppSettings {
  apiKey: string;
  theme: 'light' | 'dark';
  enableReminders: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, DocStatus, IncidentType } from "../types";

const incidentSchema = {
  type: Type.OBJECT,
  properties: {
    nature_incident: { 
      type: Type.STRING, 
      enum: [
        "Incendie", "Dégât des eaux", "Vandalisme", "Accident de travail", 
        "Panne technique", "Vol / Effraction", "Sinistre électrique", "Autre"
      ] 
    },
    date_incident: { type: Type.STRING, description: "Format YYYY-MM-DD" },
    heure_incident: { type: Type.STRING, description: "Format HH:mm" },
    lieu: { type: Type.STRING },
    objet: { type: Type.STRING, description: "Titre court de l'incident" },
    emetteur: { type: Type.STRING, description: "Agent ou déclarant" },
    reference_dossier: { type: Type.STRING },
    description_faits: { type: Type.STRING, description: "Résumé factuel des événements" },
    dommages_constates: { type: Type.STRING, description: "Liste des dégâts matériels ou humains" },
    mesures_urgentes: { type: Type.STRING, description: "Actions immédiates entreprises" },
    rapport_technique: { 
      type: Type.STRING, 
      description: "Rapport d'enquête détaillé de plus de 300 mots structuré en paragraphes (Contexte, Analyse technique, Causes probables, Recommandations)." 
    },
  },
  required: ["nature_incident", "lieu", "date_incident", "description_faits", "rapport_technique"],
};

export const analyzeIncident = async (
  apiKey: string,
  base64Data: string,
  mimeType: string,
  userInstructions: string = ""
): Promise<Partial<DocumentData>> => {
  if (!apiKey) throw new Error("Clé API manquante");

  const ai = new GoogleGenAI({ apiKey });
  const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;

  const prompt = `
    Analyse cette photo d'avis d'incident technique ou de constat.
    1. Extrais toutes les informations factuelles (Lieu, Date, Nature).
    2. Rédige un RAPPORT D'ENQUÊTE TECHNIQUE exhaustif de plus de 300 mots.
    Le rapport doit être professionnel, précis et structuré. 
    ${userInstructions ? `Instructions spécifiques : ${userInstructions}` : ''}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: incidentSchema,
        temperature: 0.2
      }
    });

    let text = response.text;
    if (!text) throw new Error("Aucune réponse de l'IA");

    text = text.replace(/```json/g, '').replace(/```/g, '').trim();
    const data = JSON.parse(text);

    return {
      ...data,
      statut: DocStatus.A_SUIVRE,
      created_at: Date.now()
    };

  } catch (error) {
    console.error("Gemini Incident Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, FileText, ArrowLeft, Trash2, Calendar, Clock, ChevronLeft, ChevronRight, X, Check, MapPin, ShieldAlert } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, deleteDocument } from '../services/db';

interface ScannerProps {
  apiKey: string;
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ apiKey, onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>("image/jpeg");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [formData, setFormData] = useState<Partial<DocumentData> | null>(null);

  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [pickerConfig, setPickerConfig] = useState<{field: keyof DocumentData, type: 'date' | 'time' | 'datetime', label: string} | null>(null);

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialData) {
        setFileData(initialData.document_image);
        setMimeType(initialData.mimeType || "image/jpeg");
        setFormData(initialData);
    }
  }, [initialData]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileData(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const performAnalysis = async () => {
    if (!apiKey) {
      alert("Clé API manquante dans les paramètres.");
      return;
    }
    if (!fileData) return;

    setAnalyzing(true);
    try {
      const result = await analyzeIncident(apiKey, fileData, mimeType);
      setFormData(prev => ({ ...prev, ...result }));
    } catch (err: any) {
      alert(`Erreur d'analyse : ${err?.message || "Inconnue"}`);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !fileData) return;
    setLoading(true);
    const finalDoc: DocumentData = {
      ...(formData as DocumentData),
      id: initialData?.id || crypto.randomUUID(),
      created_at: initialData?.created_at || Date.now(),
      document_image: fileData,
      mimeType: mimeType,
      statut: formData.statut || DocStatus.A_SUIVRE
    };

    try {
      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde locale.");
    } finally {
      setLoading(false);
    }
  };

  if (!fileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 space-y-8 bg-white dark:bg-slate-950">
        <div className="text-center space-y-2">
            <ShieldAlert size={64} className="text-brand mx-auto mb-4" />
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white uppercase tracking-tight">Nouvel Incident</h2>
            <p className="text-slate-500 dark:text-slate-400">Capturez l'avis ou le constat terrain</p>
        </div>

        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleFileChange} />

        <button 
            onClick={() => cameraInputRef.current?.click()}
            className="w-56 h-56 rounded-full bg-brand/10 border-8 border-brand flex flex-col items-center justify-center shadow-2xl active:scale-95 transition-all"
        >
            <Camera size={56} className="text-brand mb-2" />
            <span className="text-brand font-black text-xl">CAPTURER</span>
        </button>

        <div className="flex flex-col w-full max-w-xs space-y-3">
            <button onClick={() => fileInputRef.current?.click()} className="flex items-center justify-center space-x-2 bg-slate-100 dark:bg-slate-800 p-4 rounded-2xl text-slate-700 dark:text-slate-300 font-bold">
                <Upload size={20} />
                <span>Importer un fichier</span>
            </button>
            <button onClick={onCancel} className="text-slate-400 p-2 font-medium">Annuler</button>
        </div>
      </div>
    );
  }

  if (analyzing) {
      return (
          <div className="flex flex-col items-center justify-center h-full space-y-4 bg-white dark:bg-slate-950">
              <div className="relative">
                  <Loader2 size={64} className="text-brand animate-spin" />
                  <Wand2 size={24} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-brand" />
              </div>
              <p className="text-xl font-bold text-slate-900 dark:text-white">Génération du Rapport d'Enquête...</p>
              <p className="text-slate-500 text-sm">Analyse des indices et rédaction par IA</p>
          </div>
      )
  }

  return (
    <div className="h-full overflow-y-auto pb-28 bg-slate-50 dark:bg-slate-950">
        <div className="relative w-full h-[40vh] bg-slate-900 flex items-center justify-center overflow-hidden">
            <img src={fileData} alt="Incident" className="w-full h-full object-contain" />
            <button onClick={() => setFileData(null)} className="absolute top-4 left-4 bg-black/50 text-white p-2 rounded-full backdrop-blur-md">
                <RefreshCw size={20} />
            </button>
            {!formData && (
                <button 
                    onClick={performAnalysis}
                    className="absolute bottom-6 bg-brand text-white px-8 py-4 rounded-full shadow-2xl font-black flex items-center space-x-3 animate-bounce"
                >
                    <Wand2 size={24} />
                    <span>ANALYSER L'INCIDENT</span>
                </button>
            )}
        </div>

        {formData && (
            <div className="p-4 space-y-6">
                <div className="flex justify-between items-center">
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Dossier d'Incident</h3>
                    <span className="bg-brand/10 text-brand px-3 py-1 rounded-full text-xs font-bold border border-brand/20">
                        {formData.nature_incident}
                    </span>
                </div>

                <div className="grid gap-4">
                    <Input label="Objet de l'incident" value={formData.objet} onChange={(v: string) => setFormData({...formData, objet: v})} />

                    <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                        <label className="block text-[10px] font-black text-brand uppercase mb-1">Nature de l'incident</label>
                        <select 
                            className="w-full text-slate-800 dark:text-slate-100 font-bold outline-none bg-transparent"
                            value={formData.nature_incident || IncidentType.AUTRE}
                            onChange={(e) => setFormData({...formData, nature_incident: e.target.value as IncidentType})}
                        >
                            {Object.values(IncidentType).map(type => (
                                <option key={type} value={type} className="dark:bg-slate-800">{type}</option>
                            ))}
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div onClick={() => setPickerConfig({field: 'date_incident', type: 'date', label: 'Date'})}>
                            <ReadOnlyDateInput label="Date" value={formData.date_incident} icon={Calendar} />
                        </div>
                        <Input label="Heure" value={formData.heure_incident} onChange={(v: string) => setFormData({...formData, heure_incident: v})} icon={Clock} />
                    </div>

                    <Input label="Lieu précis" value={formData.lieu} onChange={(v: string) => setFormData({...formData, lieu: v})} icon={MapPin} />

                    <TextArea label="Description des faits" value={formData.description_faits} onChange={(v: string) => setFormData({...formData, description_faits: v})} rows={3} />
                    <TextArea label="Dommages constatés" value={formData.dommages_constates} onChange={(v: string) => setFormData({...formData, dommages_constates: v})} />

                    <div className="bg-brand/5 dark:bg-brand/10 p-4 rounded-3xl border-2 border-brand/20">
                        <label className="block text-xs font-black text-brand uppercase mb-2 flex items-center gap-2">
                            <ShieldAlert size={14} /> Rapport d'Enquête Technique (IA)
                        </label>
                        <textarea 
                            className="w-full h-80 bg-transparent text-sm text-slate-800 dark:text-slate-200 leading-relaxed outline-none border-none resize-none"
                            value={formData.rapport_technique}
                            onChange={(e) => setFormData({...formData, rapport_technique: e.target.value})}
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4 pt-4">
                        <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
                            <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Statut</label>
                            <select 
                                className="w-full text-slate-800 dark:text-slate-100 font-bold outline-none bg-transparent"
                                value={formData.statut}
                                onChange={(e) => setFormData({...formData, statut: e.target.value as DocStatus})}
                            >
                                <option value={DocStatus.A_SUIVRE}>À SUIVRE</option>
                                <option value={DocStatus.CLASSE}>CLASSÉ</option>
                            </select>
                        </div>
                    </div>
                </div>

                <div className="fixed bottom-24 right-4 left-4 z-40">
                     <button 
                        onClick={handleSave}
                        disabled={loading}
                        className="w-full bg-brand text-white py-5 rounded-2xl shadow-2xl font-black text-xl flex justify-center items-center space-x-3 active:scale-95 transition-transform"
                     >
                         {loading ? <Loader2 className="animate-spin" /> : <Save />}
                         <span>ENREGISTRER LE DOSSIER</span>
                     </button>
                </div>
            </div>
        )}

        {pickerConfig && (
            <CustomDateTimePicker 
                label={pickerConfig.label}
                type={pickerConfig.type}
                initialValue={formData?.[pickerConfig.field] as string}
                onClose={() => setPickerConfig(null)}
                onSelect={(val: string) => {
                    setFormData(prev => ({...prev, [pickerConfig.field]: val}));
                    setPickerConfig(null);
                }}
            />
        )}
    </div>
  );
};

// Atoms UI
