import React, { useEffect, useState } from 'react';
import { Search, Filter, Download, MoreVertical, Edit, Trash2, Printer, X, Loader2, ShieldAlert, CheckCircle } from 'lucide-react';
import { DocumentData, DocStatus } from '../types';
import { getAllDocuments, deleteDocument } from '../services/db';
import * as XLSX from 'xlsx';
import { jsPDF } from "jspdf";

interface DashboardProps {
    onEdit: (doc: DocumentData) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onEdit }) => {
    const [documents, setDocuments] = useState<DocumentData[]>([]);
    const [filteredDocs, setFilteredDocs] = useState<DocumentData[]>([]);
    const [search, setSearch] = useState("");
    const [filterStatus, setFilterStatus] = useState<"ALL" | DocStatus>("ALL");
    const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
    const [generatingPdf, setGeneratingPdf] = useState(false);

    useEffect(() => {
        loadData();
    }, []);

    useEffect(() => {
        let res = documents;
        if (search) {
            const lower = search.toLowerCase();
            res = res.filter(d => 
                d.objet.toLowerCase().includes(lower) || 
                d.lieu.toLowerCase().includes(lower) ||
                (d.nature_incident || "").toLowerCase().includes(lower)
            );
        }
        if (filterStatus !== "ALL") {
            res = res.filter(d => d.statut === filterStatus);
        }
        setFilteredDocs(res);
    }, [search, filterStatus, documents]);

    const loadData = async () => {
        const docs = await getAllDocuments();
        setDocuments(docs);
    };

    const handleGeneratePDF = async (doc: DocumentData, e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setMenuOpenId(null);
        setGeneratingPdf(true);

        try {
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pageWidth = pdf.internal.pageSize.getWidth();
            const margin = 15;
            let cursorY = 20;

            // --- HEADER ---
            pdf.setFillColor(255, 107, 0);
            pdf.rect(0, 0, pageWidth, 40, 'F');
            pdf.setTextColor(255, 255, 255);
            pdf.setFontSize(22);
            pdf.setFont("helvetica", "bold");
            pdf.text("RAPPORT D'INCIDENT OFFICIEL", margin, 20);
            pdf.setFontSize(10);
            pdf.text(`RÉFÉRENCE : ${doc.reference_dossier || doc.id.substring(0,8).toUpperCase()}`, margin, 30);
            pdf.text(`GÉNÉRÉ LE : ${new Date().toLocaleDateString()}`, pageWidth - 60, 30);

            cursorY = 55;

            // --- TABLEAU 9 POINTS (GRILLE ADMINISTRATIVE) ---
            pdf.setTextColor(40, 40, 40);
            pdf.setFontSize(12);
            pdf.text("I. INFORMATIONS GÉNÉRALES (SYNTHÈSE)", margin, cursorY);
            cursorY += 5;
            pdf.setDrawColor(200, 200, 200);
            pdf.line(margin, cursorY, pageWidth - margin, cursorY);
            cursorY += 10;

            const gridData = [
                ["Nature", doc.nature_incident],
                ["Date", doc.date_incident],
                ["Heure", doc.heure_incident],
                ["Lieu", doc.lieu],
                ["Agent", doc.emetteur || "Non renseigné"],
                ["Objet", doc.objet],
                ["Statut", doc.statut],
                ["Gravité", "À évaluer"],
                ["Réf. Dossier", doc.reference_dossier || "-"]
            ];

            pdf.setFontSize(9);
            let gridX = margin;
            let gridY = cursorY;
            gridData.forEach((item, index) => {
                const col = index % 3;
                const row = Math.floor(index / 3);
                const xPos = margin + (col * ((pageWidth - 2 * margin) / 3));
                const yPos = gridY + (row * 15);

                pdf.setFont("helvetica", "bold");
                pdf.text(item[0].toUpperCase(), xPos, yPos);
                pdf.setFont("helvetica", "normal");
                pdf.text(item[1] || "-", xPos, yPos + 5);
            });

            cursorY += 50;

            // --- FAITS ET DOMMAGES ---
            pdf.setFont("helvetica", "bold");
            pdf.setFontSize(12);
            pdf.text("II. DESCRIPTION DES FAITS & DOMMAGES", margin, cursorY);
            cursorY += 8;
            pdf.setFont("helvetica", "normal");
            pdf.setFontSize(10);
            const facts = pdf.splitTextToSize(doc.description_faits || "Aucune description fournie.", pageWidth - 2 * margin);
            pdf.text(facts, margin, cursorY);
            cursorY += (facts.length * 5) + 5;

            pdf.setFont("helvetica", "bold");
            pdf.text("DOMMAGES CONSTATÉS :", margin, cursorY);
            cursorY += 5;
            pdf.setFont("helvetica", "normal");
            const damages = pdf.splitTextToSize(doc.dommages_constates || "Néant.", pageWidth - 2 * margin);
            pdf.text(damages, margin, cursorY);
            cursorY += (damages.length * 5) + 15;

            // --- RAPPORT TECHNIQUE DÉTAILLÉ ---
            if (cursorY > 240) { pdf.addPage(); cursorY = 20; }
            pdf.setFillColor(245, 245, 245);
            pdf.rect(margin - 2, cursorY - 5, pageWidth - 2 * margin + 4, 10, 'F');
            pdf.setFont("helvetica", "bold");
            pdf.setFontSize(12);
            pdf.setTextColor(255, 107, 0);
            pdf.text("III. RAPPORT D'ENQUÊTE TECHNIQUE (IA)", margin, cursorY);
            pdf.setTextColor(40, 40, 40);
            cursorY += 10;
            pdf.setFont("helvetica", "normal");
            pdf.setFontSize(10);

            const reportLines = pdf.splitTextToSize(doc.rapport_technique || "Le rapport n'a pas été généré.", pageWidth - 2 * margin);

            // Handle multi-page for long report
            reportLines.forEach((line: string) => {
                if (cursorY > 280) {
                    pdf.addPage();
                    cursorY = 20;
                }
                pdf.text(line, margin, cursorY);
                cursorY += 5;
            });

            // --- ANNEXE PHOTO ---
            if (doc.document_image) {
                pdf.addPage();
                pdf.setFont("helvetica", "bold");
                pdf.text("ANNEXE : PIÈCE JOINTE / PREUVE PHOTOGRAPHIQUE", margin, 20);
                try {
                    pdf.addImage(doc.document_image, 'JPEG', margin, 30, pageWidth - 2 * margin, 120);
                } catch (e) {
                    pdf.text("[Erreur d'insertion de l'image]", margin, 40);
                }
            }

            pdf.save(`AVISAI_${doc.nature_incident.replace(/\s/g, '_')}_${doc.date_incident}.pdf`);
        } catch (err) {
            console.error(err);
            alert("Erreur PDF : " + err);
        } finally {
