interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

// Removed apiKey prop as per guidelines to use process.env.API_KEY exclusively
export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>("image/jpeg");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [formData, setFormData] = useState<Partial<DocumentData> | null>(null);

  const [pickerConfig, setPickerConfig] = useState<{field: keyof DocumentData, type: 'date' | 'time' | 'datetime', label: string} | null>(null);

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialData) {
        setFileData(initialData.document_image);
        setMimeType(initialData.mimeType || "image/jpeg");
        setFormData(initialData);
    }
  }, [initialData]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => {
        setFileData(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const performAnalysis = async () => {
    if (!fileData) return;

    setAnalyzing(true);
    try {
      // API Key is now strictly handled inside the analyzeIncident service using process.env.API_KEY
      const result = await analyzeIncident(fileData, mimeType);
      setFormData(prev => ({ ...prev, ...result }));
    } catch (err: any) {
      alert(`Erreur d'analyse : ${err?.message || "Inconnue"}`);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !fileData) return;
    setLoading(true);
    const finalDoc: DocumentData = {
      ...(formData as DocumentData),
      id: initialData?.id || crypto.randomUUID(),
      created_at: initialData?.created_at || Date.now(),
      document_image: fileData,
      mimeType: mimeType,
      statut: formData.statut || DocStatus.A_SUIVRE
    };

    try {
      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde locale.");
    } finally {
      setLoading(false);
    }
  };

  if (!fileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 space-y-8 bg-white dark:bg-slate-950">
        <div className="text-center space-y-2">
            <ShieldAlert size={64} className="text-brand mx-auto mb-4" />
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white uppercase tracking-tight">Nouvel Incident</h2>
            <p className="text-slate-500 dark:text-slate-400">Capturez l'avis ou le constat terrain</p>
        </div>

        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleChange => handleFileChange(handleChange)} />

        <button 
            onClick={() => cameraInputRef.current?.click()}
            className="w-56 h-56 rounded-full bg-brand/10 border-8 border-brand flex flex-col items-center justify-center shadow-2xl active:scale-95 transition-all"
        >
            <Camera size={56} className="text-brand mb-2" />
            <span className="text-brand font-black text-xl">CAPTURER</span>
        </button>

        <div className="flex flex-col w-full max-w-xs space-y-3">
            <button onClick={() => fileInputRef.current?.click()} className="flex items-center justify-center space-x-2 bg-slate-100 dark:bg-slate-800 p-4 rounded-2xl text-slate-700 dark:text-slate-300 font-bold">
                <Upload size={20} />
                <span>Importer un fichier</span>
            </button>
            <button onClick={onCancel} className="text-slate-400 p-2 font-medium">Annuler</button>
        </div>
      </div>
    );
  }

  if (analyzing) {
      return (
          <div className="flex flex-col items-center justify-center h-full space-y-4 bg-white dark:bg-slate-950">
              <div className="relative">
                  <Loader2 size={64} className="text-brand animate-spin" />
                  <Wand2 size={24} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-brand" />
              </div>
              <p className="text-xl font-bold text-slate-900 dark:text-white">Génération du Rapport d'Enquête...</p>
              <p className="text-slate-500 text-sm">Analyse des indices et rédaction par IA</p>
          </div>
      )
  }

  return (
    <div className="h-full overflow-y-auto pb-28 bg-slate-50 dark:bg-slate-950">
        <div className="relative w-full h-[40vh] bg-slate-900 flex items-center justify-center overflow-hidden">
            <img src={fileData} alt="Incident" className="w-full h-full object-contain" />
            <button onClick={() => setFileData(null)} className="absolute top-4 left-4 bg-black/50 text-white p-2 rounded-full backdrop-blur-md">
                <RefreshCw size={20} />
            </button>
            {!formData && (
                <button 
                    onClick={performAnalysis}
                    className="absolute bottom-6 bg-brand text-white px-8 py-4 rounded-full shadow-2xl font-black flex items-center space-x-3 animate-bounce"
                >
                    <Wand2 size={24} />
                    <span>ANALYSER L'INCIDENT</span>
                </button>
            )}
        </div>

        {formData && (
            <div className="p-4 space-y-6">
                <div className="flex justify-between items-center">
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Dossier d'Incident</h3>
                    <span className="bg-brand/10 text-brand px-3 py-1 rounded-full text-xs font-bold border border-brand/20">
                        {formData.nature_incident}
                    </span>
                </div>

                <div className="grid gap-4">
                    <Input label="Objet de l'incident" value={formData.objet} onChange={(v: string) => setFormData({...formData, objet: v})} />

                    <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                        <label className="block text-[10px] font-black text-brand uppercase mb-1">Nature de l'incident</label>
