interface SettingsProps {
    enableReminders: boolean;
    setEnableReminders: (val: boolean) => void;
    theme: 'light' | 'dark';
    setTheme: (t: 'light' | 'dark') => void;
}

// Removed apiKey management UI components and logic as per guidelines
export const Settings: React.FC<SettingsProps> = ({ enableReminders, setEnableReminders, theme, setTheme }) => {
    const [isRestoring, setIsRestoring] = useState(false);

    const handleBackup = async () => {
        try {
            const docs = await getAllDocuments();
            if (docs.length === 0) {
                alert("Aucune donnée à sauvegarder.");
                return;
            }
            const json = JSON.stringify(docs, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `secapp_backup_${new Date().toISOString().split('T')[0]}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch (e) {
            console.error(e);
            alert("Erreur lors de la création de la sauvegarde.");
        }
    };

    const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!window.confirm(`Voulez-vous restaurer le fichier "${file.name}" ?\nAttention : Les données actuelles seront fusionnées.`)) {
            e.target.value = "";
            return;
        }

        setIsRestoring(true);
        const reader = new FileReader();

        reader.onload = async (event) => {
            try {
                const json = event.target?.result as string;
                if (!json) throw new Error("Fichier vide.");

                const data = JSON.parse(json);
                if (!Array.isArray(data)) throw new Error("Format invalide.");

                const count = await restoreBackup(data as DocumentData[]);
                alert(`${count} documents restaurés.`);
                window.location.reload();
            } catch (err: any) {
                console.error(err);
                alert("Erreur: " + err.message);
            } finally {
                setIsRestoring(false);
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="h-full bg-gray-50 dark:bg-slate-950 p-6 overflow-y-auto transition-colors duration-300">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white mb-8">Paramètres</h2>

            {isRestoring && (
                <div className="fixed inset-0 bg-black/60 z-[100] flex flex-col items-center justify-center text-white backdrop-blur-sm">
                    <Loader2 size={48} className="animate-spin mb-4 text-[#0ABAB5]" />
                    <p className="font-bold text-xl">Restauration en cours...</p>
                </div>
            )}

            {/* PREFERENCES SECTION */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-transparent dark:border-slate-800 p-6 space-y-6 mb-6 transition-colors duration-300">
                <div className="flex items-center space-x-2 text-[#FF6600]">
                    <Bell size={24} />
                    <h3 className="font-bold text-lg">Préférences</h3>
                </div>

                {/* Toggle Reminders */}
                <div className="flex items-center justify-between border-b border-gray-100 dark:border-slate-800 pb-4">
                    <span className="text-gray-700 dark:text-gray-200 text-sm font-medium">Activer les rappels visuels</span>
                    <div 
                        onClick={() => setEnableReminders(!enableReminders)}
                        className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors ${enableReminders ? 'bg-[#0ABAB5]' : 'bg-gray-300 dark:bg-gray-600'}`}
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform ${enableReminders ? 'translate-x-6' : ''}`}></div>
                    </div>
                </div>

                {/* Toggle Dark Mode */}
                <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-2">
                        {theme === 'dark' ? <Moon size={18} className="text-purple-400"/> : <Sun size={18} className="text-orange-400"/>}
                        <span className="text-gray-700 dark:text-gray-200 text-sm font-medium">Mode Sombre</span>
                    </div>
                    <div 
                        onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')}
                        className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors ${theme === 'dark' ? 'bg-purple-600' : 'bg-gray-300 dark:bg-gray-600'}`}
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform ${theme === 'dark' ? 'translate-x-6' : ''}`}></div>
                    </div>
                </div>
            </div>

            {/* DATA SECTION */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-transparent dark:border-slate-800 p-6 space-y-6 transition-colors duration-300">
                <div className="flex items-center space-x-2 text-gray-700 dark:text-gray-300">
                    <Database size={24} />
                    <h3 className="font-bold text-lg">Données</h3>
                </div>
                <p className="text-sm text-gray-600 dark:text-gray-400">
                    Gestion des sauvegardes locales (JSON).
                </p>

                <div className="grid grid-cols-1 gap-4">
                    <button 
                        onClick={handleBackup}
                        disabled={isRestoring}
                        className="w-full bg-gray-800 dark:bg-slate-700 text-white font-bold py-3 rounded-xl shadow-md active:scale-95 transition-transform flex justify-center items-center space-x-2"
                    >
                        <Download size={18} />
                        <span>Sauvegarder mes données</span>
                    </button>

                    <label className={`w-full bg-white dark:bg-slate-800 border-2 border-gray-200 dark:border-slate-700 text-gray-700 dark:text-gray-300 font-bold py-3 rounded-xl hover:bg-gray-50 dark:hover:bg-slate-700 active:scale-95 transition-transform flex justify-center items-center space-x-2 cursor-pointer ${isRestoring ? 'opacity-50' : ''}`}>
                        <UploadCloud size={18} />
                        <span>Restaurer une sauvegarde</span>
                        <input 
                            type="file" 
                            accept=".json"
                            className="hidden"
                            onChange={handleRestore}
                            disabled={isRestoring}
                        />
                    </label>
                </div>
            </div>

            <div className="mt-8 text-center pb-6">
                <p className="text-xs text-gray-400 dark:text-gray-600 font-mono">Sécapp AI v1.2.0 (Environment Config)</p>
            </div>
