import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, DocStatus, IncidentType } from "../types";

const incidentSchema = {
  type: Type.OBJECT,
  properties: {
    victime_objet: { type: Type.STRING, description: "1-Victime ou objet du sinistre" },
    description_sinistre: { type: Type.STRING, description: "2-Description du sinistre" },
    lieu_date_heure: { type: Type.STRING, description: "3-Lieu, date et heure du sinistre" },
    dommages: { type: Type.STRING, description: "4-Dommages (nature et évaluation sommaire)" },
    causes_circonstances: { type: Type.STRING, description: "5-Causes et circonstances détaillées" },
    responsabilites: { type: Type.STRING, description: "6-Responsabilités" },
    mesures_prises: { type: Type.STRING, description: "7-Mesures prises pour la limitation ou la réparation" },
    references_autorites: { type: Type.STRING, description: "8-Références (autorités informées, dépôt de plainte)" },
    observations: { type: Type.STRING, description: "9-Observations" },
    nature_incident: { type: Type.STRING, enum: Object.values(IncidentType) },
    date_iso: { type: Type.STRING, description: "Date au format YYYY-MM-DD pour le calcul du numéro de dossier" }
  },
  required: ["victime_objet", "description_sinistre", "lieu_date_heure", "nature_incident", "date_iso"],
};

export const analyzeIncident = async (
  base64Data: string,
  mimeType: string,
  userNotes: string = ""
): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;

  const prompt = `
    Analyse ce document d'incident technique. 
    1. Extrais précisément les informations pour remplir les 9 rubriques administratives.
    2. Utilise les notes complémentaires de l'utilisateur pour enrichir l'analyse : "${userNotes}"
    3. Identifie la date pour générer le champ date_iso (YYYY-MM-DD).
    4. Sois très formel et technique dans la rédaction.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: incidentSchema,
        temperature: 0.1
      }
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || null);

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const generateSRMId = async (dateIso: string) => {
    const date = new Date(dateIso);
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = String(date.getFullYear()).slice(-2);
    const prefix = `SRM-MS/DPH/AI-${month}${year}`;

    const docs = await getAllDocuments();
    const monthlyDocs = docs.filter(d => d.id.startsWith(prefix));
    const counter = monthlyDocs.length + 1;
    return `${prefix}${counter}`;
  };

  const performAnalysis = async () => {
    if (!fileData) return;
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ ...prev, ...result }));
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !fileData) return;
    setLoading(true);
    try {
      const dateIso = formData.date_iso || new Date().toISOString().split('T')[0];
      const srmId = (initialData && !initialData.id.startsWith('TEMP')) 
        ? initialData.id 
        : await generateSRMId(dateIso);

      const isClassed = formData.statut === DocStatus.CLASSE;

      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: srmId,
        document_image: fileData,
        mimeType: mimeType,
        aux_images: auxImages,
        statut: formData.statut || DocStatus.A_SUIVRE,
        rappel_actif: !isClassed,
        created_at: initialData?.created_at || Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!fileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 space-y-6 bg-white dark:bg-slate-950">
        <div className="text-center">
            <ShieldAlert size={64} className="text-brand mx-auto mb-4" />
            <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Capture d'Avis</h2>
        </div>

        <div className="w-full space-y-4 max-w-sm">
            <textarea 
                className="w-full p-4 bg-slate-100 dark:bg-slate-900 rounded-2xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white"
                placeholder="Description rapide de l'incident (ex: Manque de neutre à Douar Ait El Hour)..."
                rows={4}
                value={userText}
