import React, { useEffect, useState } from 'react';
import { Search, Filter, Download, Trash2, Printer, Loader2, ShieldAlert, CheckCircle, Copy, Bell, BellOff } from 'lucide-react';
import { DocumentData, DocStatus } from '../types';
import { getAllDocuments, deleteDocument } from '../services/db';
import * as XLSX from 'xlsx';
import { jsPDF } from "jspdf";

interface DashboardProps {
    onEdit: (doc: DocumentData) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onEdit }) => {
    const [documents, setDocuments] = useState<DocumentData[]>([]);
    const [filteredDocs, setFilteredDocs] = useState<DocumentData[]>([]);
    const [search, setSearch] = useState("");
    const [filterStatus, setFilterStatus] = useState<"ALL" | DocStatus>("ALL");
    const [generatingPdf, setGeneratingPdf] = useState(false);

    useEffect(() => { loadData(); }, []);

    useEffect(() => {
        let res = documents;
        if (search) {
            const lower = search.toLowerCase();
            res = res.filter(d => 
                d.id.toLowerCase().includes(lower) || 
                d.victime_objet.toLowerCase().includes(lower) ||
                d.lieu_date_heure.toLowerCase().includes(lower)
            );
        }
        if (filterStatus !== "ALL") res = res.filter(d => d.statut === filterStatus);
        setFilteredDocs(res);
    }, [search, filterStatus, documents]);

    const loadData = async () => setDocuments(await getAllDocuments());

    const handleDuplicate = (doc: DocumentData, e: React.MouseEvent) => {
        e.stopPropagation();
        const duplicated = { ...doc, id: `TEMP_${Date.now()}`, created_at: Date.now() };
        onEdit(duplicated);
    };

    const handleGeneratePDF = async (doc: DocumentData, e: React.MouseEvent) => {
        e.stopPropagation();
        setGeneratingPdf(true);
        try {
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pageWidth = pdf.internal.pageSize.getWidth();
            const margin = 10;
            let currentY = 15;

            // --- HEADER (Conforme au modèle) ---
            pdf.setFontSize(8);
            pdf.setTextColor(51, 102, 204);
            pdf.text("الشركة الجهوية متعددة الخدمات مراكش - آسفي ش.م", pageWidth / 2, currentY, { align: "center" });
            currentY += 4;
            pdf.text("Société Régionale Multiservices Marrakech-Safi SA", pageWidth / 2, currentY, { align: "center" });
            currentY += 10;

            pdf.setFontSize(14);
            pdf.setFont("helvetica", "bold");
            pdf.setTextColor(0, 0, 0);
            pdf.text("Monsieur le Directeur Général", pageWidth / 2, currentY, { align: "center" });
            currentY += 10;
            pdf.text(`AVIS D'INCIDENT N°: ${doc.id}`, pageWidth / 2, currentY, { align: "center" });
            currentY += 10;

            // --- TABLEAU ENCADRÉ ---
            const rubrics = [
                { label: "1-Victime ou objet du sinistre", value: doc.victime_objet },
                { label: "2-Description du sinistre", value: doc.description_sinistre },
                { label: "3-Lieu, date et heure du sinistre", value: doc.lieu_date_heure },
                { label: "4-Dommages (nature et évaluation sommaire)", value: doc.dommages },
                { label: "5-Causes et circonstances détaillées du sinistre", value: doc.causes_circonstances },
                { label: "6-Responsabilités", value: doc.responsabilites },
                { label: "7-Mesures prises pour la limitation ou la réparation", value: doc.mesures_prises },
                { label: "8-Références (autorités informées, dépôt de plainte)", value: doc.references_autorites },
                { label: "9-Observations", value: doc.observations }
            ];

            const col1Width = 50;
            const col2Width = pageWidth - 2 * margin - col1Width;

            pdf.setFontSize(9);
            rubrics.forEach(rubric => {
                const textLines = pdf.splitTextToSize(rubric.value || " ", col2Width - 4);
                const cellHeight = Math.max(12, textLines.length * 5 + 4);

                if (currentY + cellHeight > 270) { pdf.addPage(); currentY = 15; }

                // Borders
                pdf.rect(margin, currentY, col1Width, cellHeight);
                pdf.rect(margin + col1Width, currentY, col2Width, cellHeight);

                // Label
                pdf.setFont("helvetica", "bold");
                const labelLines = pdf.splitTextToSize(rubric.label, col1Width - 4);
                pdf.text(labelLines, margin + 2, currentY + 6);

                // Value
                pdf.setFont("helvetica", "normal");
                pdf.text(textLines, margin + col1Width + 2, currentY + 6);

                currentY += cellHeight;
            });

            // --- SIGNATURES ---
            currentY += 15;
            pdf.setFontSize(10);
            pdf.setFont("helvetica", "normal");
            pdf.text(`Fait à Tahannaoute : ${new Date().toLocaleDateString()}`, margin, currentY);
            currentY += 10;
            pdf.setFont("helvetica", "bold");
            pdf.text("Signature du Chef de l'entité", margin + 10, currentY);
            pdf.text("Signature du chef de la Division", pageWidth - margin - 60, currentY);

            // --- IMAGES ANNEXES ---
            if (doc.document_image || (doc.aux_images && doc.aux_images.length > 0)) {
                pdf.addPage();
                pdf.text("ANNEXES PHOTOGRAPHIQUES", pageWidth / 2, 15, { align: "center" });
                let imgY = 25;
                const images = [doc.document_image, ...(doc.aux_images || [])];
                images.forEach((img, idx) => {
                    if (!img) return;
                    if (imgY + 80 > 280) { pdf.addPage(); imgY = 20; }
                    try {
                        pdf.addImage(img, 'JPEG', margin + 20, imgY, pageWidth - 2 * margin - 40, 70);
                        imgY += 85;
                    } catch(e) { console.error("PDF Image Error", e); }
                });
            }

            pdf.save(`AVISAI_${doc.id.replace(/\//g, '-')}.pdf`);
        } catch (err) { alert("Erreur PDF : " + err); }
        finally { setGeneratingPdf(false); }
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirm("Supprimer définitivement cet avis ?")) {
            await deleteDocument(id);
            loadData();
        }
    };

    return (
        <div className="h-full bg-slate-50 dark:bg-slate-950 flex flex-col">
            {generatingPdf && (
                <div className="fixed inset-0 bg-black/80 z-[100] flex flex-col items-center justify-center text-white backdrop-blur-sm">
                    <Loader2 size={48} className="animate-spin text-brand mb-4" />
                    <p className="font-black text-xl">PRODUCTION DU TABLEAU PDF...</p>
                </div>
            )}

            <div className="bg-white dark:bg-slate-900 p-4 shadow-sm z-10 border-b border-slate-200 dark:border-slate-800">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter uppercase">Archives</h2>
                    <button onClick={() => {
                        const ws = XLSX.utils.json_to_sheet(documents.map(({document_image, aux_images, ...rest}) => rest));
                        const wb = XLSX.utils.book_new();
                        XLSX.utils.book_append_sheet(wb, ws, "Incidents");
                        XLSX.writeFile(wb, "Avisai_Report.xlsx");
                    }} className="text-brand p-2 bg-brand/10 rounded-xl"><Download size={22} /></button>
                </div>

                <div className="flex gap-2">
                    <div className="flex-1 relative">
                        <Search className="absolute left-3 top-3 text-slate-400" size={18} />
                        <input className="w-full bg-slate-100 dark:bg-slate-800 rounded-2xl pl-10 pr-4 py-3 text-sm outline-none focus:ring-2 ring-brand text-slate-800 dark:text-white" placeholder="N° Avis, Lieu, Objet..." value={search} onChange={e => setSearch(e.target.value)} />
                    </div>
                    <button className={`p-3 rounded-2xl ${filterStatus !== 'ALL' ? 'bg-brand text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-600'}`} onClick={() => setFilterStatus(filterStatus === 'ALL' ? DocStatus.A_SUIVRE : filterStatus === DocStatus.A_SUIVRE ? DocStatus.CLASSE : "ALL")}>
                        <Filter size={20} />
                    </button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-24">
                {filteredDocs.map(doc => (
                    <div key={doc.id} onClick={() => onEdit(doc)} className={`bg-white dark:bg-slate-900 rounded-3xl shadow-sm p-5 border-l-8 transition-all active:scale-95 ${doc.statut === DocStatus.CLASSE ? 'border-green-500' : 'border-brand shadow-brand/10'}`}>
                        <div className="flex justify-between items-start mb-2">
                            <div className="flex-1">
                                <div className="flex items-center gap-2 mb-1">
                                    <ShieldAlert size={14} className={doc.statut === DocStatus.CLASSE ? 'text-green-500' : 'text-brand'} />
                                    <span className={`text-[10px] font-black uppercase ${doc.statut === DocStatus.CLASSE ? 'text-green-600' : 'text-brand'}`}>{doc.id}</span>
                                </div>
                                <h3 className="font-black text-slate-900 dark:text-gray-100 leading-tight uppercase tracking-tight">{doc.victime_objet}</h3>
                                <p className="text-xs text-slate-500 font-bold">{doc.lieu_date_heure}</p>
                            </div>
                            <div className="flex flex-col items-end">
                                {doc.rappel_actif ? <Bell size={18} className="text-brand animate-pulse" /> : <BellOff size={18} className="text-slate-300" />}
                            </div>
                        </div>

                        <p className="text-xs text-slate-600 dark:text-slate-400 line-clamp-2 mt-2 italic">"{doc.description_sinistre}"</p>

                        <div className="flex items-center justify-between mt-4">
                             <span className={`text-[10px] font-black px-3 py-1 rounded-full border ${doc.statut === DocStatus.CLASSE ? 'bg-green-50 text-green-600 border-green-200' : 'bg-orange-50 text-brand border-brand/20'}`}>
                                 {doc.statut.toUpperCase()}
                             </span>
                             <div className="flex gap-2">
                                <button onClick={e => handleDuplicate(doc, e)} className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-full text-blue-600" title="Dupliquer"><Copy size={18}/></button>
                                <button onClick={e => handleGeneratePDF(doc, e)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-600"><Printer size={18}/></button>
                                <button onClick={e => handleDelete(doc.id, e)} className="p-2 bg-red-50 dark:bg-red-900/20 rounded-full text-red-500"><Trash2 size={18}/></button>
                             </div>
                        </div>
                    </div>
                ))}
                {filteredDocs.length === 0 && (
                    <div className="flex flex-col items-center justify-center pt-20 text-slate-400">
                        <CheckCircle size={48} className="mb-4 opacity-20" />
                        <p className="font-bold">Aucun dossier trouvé.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

