import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, IncidentType } from "../types";

const incidentSchema = {
  type: Type.OBJECT,
  properties: {
    victime_objet: { type: Type.STRING, description: "1-Victime ou objet du sinistre" },
    description_sinistre: { type: Type.STRING, description: "2-Description du sinistre" },
    lieu_date_heure: { type: Type.STRING, description: "3-Lieu, date et heure du sinistre" },
    dommages: { type: Type.STRING, description: "4-Dommages (nature et évaluation sommaire)" },
    causes_circonstances: { type: Type.STRING, description: "5-Causes et circonstances détaillées" },
    responsabilites: { type: Type.STRING, description: "6-Responsabilités" },
    mesures_prises: { type: Type.STRING, description: "7-Mesures prises pour la limitation ou la réparation" },
    references_autorites: { type: Type.STRING, description: "8-Références (autorités informées, dépôt de plainte)" },
    observations: { type: Type.STRING, description: "9-Observations" },
    nature_incident: { type: Type.STRING, enum: Object.values(IncidentType) },
    date_iso: { type: Type.STRING, description: "Date au format YYYY-MM-DD extraite du document" }
  },
  required: ["victime_objet", "description_sinistre", "lieu_date_heure", "nature_incident", "date_iso"],
};

export const analyzeIncident = async (
  base64Data: string,
  mimeType: string,
  userNotes: string = ""
): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;

  const prompt = `
    Analyse ce document d'incident technique (ou utilise les notes fournies si le document est illisible).
    1. Extrais précisément les informations pour remplir les 9 rubriques administratives SRM.
    2. Utilise ces notes complémentaires de l'utilisateur pour enrichir ou remplir les champs : "${userNotes}"
    3. Identifie la date pour générer le champ date_iso (YYYY-MM-DD).
    4. Adopte un ton très professionnel et technique.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: incidentSchema,
        temperature: 0.1
      }
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || null);

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const generateSRMId = async (dateIso: string) => {
    const date = new Date(dateIso);
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = String(date.getFullYear()).slice(-2);
    const monthYearPrefix = `${month}${year}`;
    const fullPrefix = `SRM-MS/DPH/AI-${monthYearPrefix}`;

    const docs = await getAllDocuments();
    // Compter combien d'incidents existent pour ce préfixe précis
    const monthlyDocs = docs.filter(d => d.id.startsWith(fullPrefix));
    const counter = monthlyDocs.length + 1;
    return `${fullPrefix}${counter}`;
  };

  const performAnalysis = async () => {
    if (!fileData) return;
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ ...prev, ...result }));
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !fileData) return;
    setLoading(true);
    try {
      const dateIso = formData.date_iso || new Date().toISOString().split('T')[0];

      // Si c'est un duplicata ou un nouvel enregistrement, on regenere l'ID si necessaire
      let srmId = formData.id;
      if (!srmId || srmId.startsWith('TEMP_')) {
        srmId = await generateSRMId(dateIso);
      }

      const isClassed = formData.statut === DocStatus.CLASSE;

      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: srmId,
        document_image: fileData,
        mimeType: mimeType,
        aux_images: auxImages,
        statut: formData.statut || DocStatus.A_SUIVRE,
        rappel_actif: !isClassed,
        created_at: initialData?.created_at || Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!fileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 space-y-6 bg-white dark:bg-slate-950">
        <div className="text-center">
            <ShieldAlert size={64} className="text-brand mx-auto mb-4" />
            <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Capture & Analyse</h2>
        </div>

        <div className="w-full space-y-4 max-w-sm">
            <label className="block text-xs font-bold text-slate-400 uppercase ml-2">Description manuelle (optionnelle)</label>
            <textarea 
                className="w-full p-4 bg-slate-100 dark:bg-slate-900 rounded-2xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white"
                placeholder="Ex: Panne transformateur Douar Ait El Hour..."
                rows={4}
                value={userText}
                onChange={e => setUserText(e.target.value)}
            />

            <div className="grid grid-cols-2 gap-4">
                <button onClick={() => cameraInputRef.current?.click()} className="flex flex-col items-center bg-brand text-white p-6 rounded-3xl shadow-lg active:scale-95 transition-transform">
                    <Camera size={32} />
                    <span className="text-[10px] font-black mt-2 uppercase">Camera</span>
                </button>
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center bg-slate-200 dark:bg-slate-800 text-slate-700 dark:text-slate-300 p-6 rounded-3xl active:scale-95 transition-transform">
                    <Upload size={32} />
                    <span className="text-[10px] font-black mt-2 uppercase">PDF / IMAGE</span>
                </button>
            </div>
            <button onClick={onCancel} className="w-full text-slate-400 font-bold text-sm py-2">ANNULER</button>
        </div>

        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
      </div>
    );
  }

  if (analyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 bg-white dark:bg-slate-950">
        <Loader2 size={48} className="text-brand animate-spin" />
        <p className="font-black text-brand uppercase tracking-widest animate-pulse">Extraction Intelligence Artificielle...</p>
      </div>
    );
  }

  return (
    <div className="h-full overflow-y-auto pb-32 bg-slate-50 dark:bg-slate-950">
      <div className="relative h-[20vh] bg-slate-900 flex items-center justify-center overflow-hidden">
        {mimeType === "application/pdf" ? (
          <div className="text-white flex flex-col items-center"><FileText size={48} /><span>Avis PDF</span></div>
        ) : (
          <img src={fileData} className="w-full h-full object-contain" />
        )}
        <button onClick={() => setFileData(null)} className="absolute top-4 left-4 bg-black/50 text-white p-2 rounded-full backdrop-blur-md">
            <RefreshCw size={18} />
        </button>
        {!formData && (
            <button onClick={performAnalysis} className="absolute bottom-4 bg-brand text-white px-8 py-3 rounded-full shadow-2xl font-black flex items-center gap-2">
                <Wand2 size={20} /> ANALYSER AVEC L'IA
            </button>
        )}
      </div>

      {formData && (
        <div className="p-4 space-y-4">
          <div className="flex justify-between items-center px-1">
            <h3 className="font-black text-brand uppercase text-[10px] tracking-widest">AVIS D'INCIDENT SRM</h3>
            <button onClick={performAnalysis} className="text-[9px] font-black bg-slate-200 dark:bg-slate-800 px-3 py-1 rounded-full flex items-center gap-1">
                <Wand2 size={10}/> RÉ-ARRANGER AVEC IA
            </button>
          </div>

          <Field label="1-Victime ou objet du sinistre" value={formData.victime_objet} onChange={v => setFormData({...formData, victime_objet: v})} />
          <Field label="2-Description du sinistre" value={formData.description_sinistre} onChange={v => setFormData({...formData, description_sinistre: v})} />
          <Field label="3-Lieu, date et heure du sinistre" value={formData.lieu_date_heure} onChange={v => setFormData({...formData, lieu_date_heure: v})} />
          <Field label="4-Dommages (nature et évaluation)" value={formData.dommages} onChange={v => setFormData({...formData, dommages: v})} />

          <div className="relative bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800 focus-within:border-brand">
            <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">5-Causes et circonstances détaillées</label>
            <textarea 
                className="w-full bg-transparent font-bold outline-none resize-none dark:text-white text-xs leading-relaxed" 
                rows={4} 
                value={formData.causes_circonstances || ""} 
                onChange={e => setFormData({...formData, causes_circonstances: e.target.value})} 
            />

            <div className="mt-3 flex gap-2 overflow-x-auto pb-2">
                {auxImages.map((img, i) => (
                    <div key={i} className="relative shrink-0 w-20 h-20 rounded-xl overflow-hidden border-2 border-brand">
                        <img src={img} className="w-full h-full object-cover" />
                        <button onClick={() => setAuxImages(auxImages.filter((_, idx) => idx !== i))} className="absolute top-0 right-0 bg-red-500 text-white p-1 rounded-bl-lg">
                            <X size={10} />
                        </button>
                    </div>
                ))}
                {auxImages.length < 3 && (
                    <button onClick={() => auxInputRef.current?.click()} className="w-20 h-20 rounded-xl border-2 border-dashed border-slate-300 dark:border-slate-700 flex flex-col items-center justify-center text-slate-400 active:bg-slate-50 transition-colors">
                        <Paperclip size={24} />
                        <span className="text-[8px] font-black mt-1">MAX 3</span>
                    </button>
                )}
            </div>
            <input type="file" accept="image/*" className="hidden" ref={auxInputRef} onChange={handleAuxImage} />
          </div>

          <Field label="6-Responsabilités" value={formData.responsabilites} onChange={v => setFormData({...formData, responsabilites: v})} />
          <Field label="7-Mesures prises (limitation/réparation)" value={formData.mesures_prises} onChange={v => setFormData({...formData, mesures_prises: v})} />
          <Field label="8-Références (autorités, plainte)" value={formData.references_autorites} onChange={v => setFormData({...formData, references_autorites: v})} />
          <Field label="9-Observations" value={formData.observations} onChange={v => setFormData({...formData, observations: v})} />

          <div className="grid grid-cols-2 gap-4">
             <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Nature Incident</label>
                <select className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" value={formData.nature_incident} onChange={e => setFormData({...formData, nature_incident: e.target.value as IncidentType})}>
                    {Object.values(IncidentType).map(t => <option key={t} value={t}>{t}</option>)}
                </select>
             </div>
             <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Statut Dossier</label>
                <select 
                  className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" 
                  value={formData.statut} 
                  onChange={e => {
                    const newStatus = e.target.value as DocStatus;
                    setFormData({...formData, statut: newStatus, rappel_actif: newStatus !== DocStatus.CLASSE});
                  }}
                >
                    <option value={DocStatus.A_SUIVRE}>À SUIVRE</option>
                    <option value={DocStatus.CLASSE}>CLASSÉ</option>
                </select>
             </div>
          </div>
        </div>
      )}

      <div className="fixed bottom-24 left-4 right-4 z-40">
        <button onClick={handleSave} disabled={loading} className="w-full bg-brand text-white py-5 rounded-3xl font-black text-xl shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-transform">
          {loading ? <Loader2 className="animate-spin" /> : <Save />} ENREGISTRER L'AVIS
        </button>
      </div>
    </div>
  );
};

