        const duplicated = { ...doc, id: `TEMP_${Date.now()}`, created_at: Date.now() };
        onEdit(duplicated);
    };

    const handleGeneratePDF = async (doc: DocumentData, e: React.MouseEvent) => {
        e.stopPropagation();
        setGeneratingPdf(true);
        try {
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pageWidth = pdf.internal.pageSize.getWidth();
            const margin = 12;
            let currentY = 15;

            // --- HEADER ---
            pdf.setFontSize(8);
            pdf.setTextColor(51, 102, 204);
            pdf.text("الشركة الجهوية متعددة الخدمات مراكش - آسفي ش.م", pageWidth / 2, currentY, { align: "center" });
            currentY += 4;
            pdf.text("Société Régionale Multiservices Marrakech-Safi SA", pageWidth / 2, currentY, { align: "center" });
            currentY += 10;

            pdf.setFontSize(13);
            pdf.setFont("helvetica", "bold");
            pdf.setTextColor(0, 0, 0);
            pdf.text("Monsieur le Directeur Général", pageWidth / 2, currentY, { align: "center" });
            currentY += 8;
            pdf.text(`AVIS D'INCIDENT N°: ${doc.id}`, pageWidth / 2, currentY, { align: "center" });
            currentY += 12;

            // --- CONFIG TABLEAU ---
            const rubrics = [
                { label: "1-Victime ou objet du sinistre", value: doc.victime_objet },
                { label: "2-Description du sinistre", value: doc.description_sinistre },
                { label: "3-Lieu, date et heure du sinistre", value: doc.lieu_date_heure },
                { label: "4-Dommage (nature et évaluation sommaire)", value: doc.dommages },
                { label: "5-Causes et circonstances détaillées du sinistre", value: doc.causes_circonstances },
                { label: "6-Responsabilités", value: doc.responsabilites },
                { label: "7-Mesures prises pour la limitation et ou réparation su sinistre", value: doc.mesures_prises },
                { label: "8-Références, date et heures de l'information des autorités compétentes et du dépôt de plainte", value: doc.references_autorites },
                { label: "9-Observations", value: doc.observations }
            ];

            const col1Width = 55;
            const col2Width = pageWidth - 2 * margin - col1Width;
            pdf.setFontSize(9);

            rubrics.forEach(rubric => {
                const textLines = pdf.splitTextToSize(rubric.value || " ", col2Width - 4);
                const labelLines = pdf.splitTextToSize(rubric.label, col1Width - 4);

                const lineHeight = 5;
                const cellHeight = Math.max(12, Math.max(textLines.length, labelLines.length) * lineHeight + 6);

                // Saut de page si nécessaire
                if (currentY + cellHeight > 275) { pdf.addPage(); currentY = 15; }

                // Dessiner les cadres
                pdf.rect(margin, currentY, col1Width, cellHeight);
                pdf.rect(margin + col1Width, currentY, col2Width, cellHeight);

                // Texte Label (Gauche)
                pdf.setFont("helvetica", "bold");
                pdf.text(labelLines, margin + 2, currentY + 6);

                // Texte Valeur (Droite)
                pdf.setFont("helvetica", "normal");
                pdf.text(textLines, margin + col1Width + 2, currentY + 6);

                currentY += cellHeight;
            });

            // --- SIGNATURES ---
            currentY += 15;
            pdf.setFontSize(10);
            pdf.setFont("helvetica", "normal");
            pdf.text(`Fait à Tahannaoute : ${new Date().toLocaleDateString()}`, margin, currentY);
            currentY += 10;
            pdf.setFont("helvetica", "bold");
            pdf.text("Signature du Chef de l'entité", margin + 15, currentY);
            pdf.text("Signature du chef de la Division", pageWidth - margin - 65, currentY);

            // --- ANNEXES ---
            const images = [doc.document_image, ...(doc.aux_images || [])].filter(Boolean);
            if (images.length > 0) {
                pdf.addPage();
                pdf.text("ANNEXES PHOTOGRAPHIQUES", pageWidth / 2, 15, { align: "center" });
                let imgY = 25;
                images.forEach((img) => {
                    if (imgY + 85 > 280) { pdf.addPage(); imgY = 20; }
                    try {
                        pdf.addImage(img, 'JPEG', margin + 15, imgY, pageWidth - 2 * margin - 30, 80);
                        imgY += 90;
                    } catch(e) { console.error(e); }
                });
            }

            pdf.save(`AVISAI_${doc.id.replace(/\//g, '-')}.pdf`);
        } catch (err) { alert("Erreur lors de la génération du PDF."); }
        finally { setGeneratingPdf(false); }
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirm("Supprimer cet avis d'incident ?")) {
            await deleteDocument(id);
            loadData();
        }
    };

    return (
        <div className="h-full bg-slate-50 dark:bg-slate-950 flex flex-col">
            {generatingPdf && (
                <div className="fixed inset-0 bg-black/80 z-[100] flex flex-col items-center justify-center text-white backdrop-blur-sm">
                    <Loader2 size={48} className="animate-spin text-brand mb-4" />
                    <p className="font-black text-xl">CONSTRUCTION DU RAPPORT SRM...</p>
                </div>
            )}

            <div className="bg-white dark:bg-slate-900 p-4 shadow-sm z-10 border-b border-slate-200 dark:border-slate-800">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Historique Avis</h2>
                    <button onClick={() => {
                        const ws = XLSX.utils.json_to_sheet(documents.map(({document_image, aux_images, ...rest}) => rest));
                        const wb = XLSX.utils.book_new();
                        XLSX.utils.book_append_sheet(wb, ws, "SRM_Incidents");
                        XLSX.writeFile(wb, "Avisai_Report.xlsx");
                    }} className="text-brand p-2 bg-brand/10 rounded-xl active:scale-90 transition-transform"><Download size={22} /></button>
                </div>

                <div className="flex gap-2">
                    <div className="flex-1 relative">
                        <Search className="absolute left-3 top-3 text-slate-400" size={18} />
                        <input className="w-full bg-slate-100 dark:bg-slate-800 rounded-2xl pl-10 pr-4 py-3 text-sm outline-none focus:ring-2 ring-brand text-slate-800 dark:text-white" placeholder="N° Avis, Lieu, Victime..." value={search} onChange={e => setSearch(e.target.value)} />
                    </div>
                    <button className={`p-3 rounded-2xl ${filterStatus !== 'ALL' ? 'bg-brand text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-600'}`} onClick={() => setFilterStatus(filterStatus === 'ALL' ? DocStatus.A_SUIVRE : filterStatus === DocStatus.A_SUIVRE ? DocStatus.CLASSE : "ALL")}>
                        <Filter size={20} />
                    </button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-24">
                {filteredDocs.map(doc => (
                    <div 
                      key={doc.id} 
                      onClick={() => onEdit(doc)} 
                      className={`bg-white dark:bg-slate-900 rounded-3xl shadow-sm p-5 border-l-[12px] transition-all active:scale-95 relative group ${doc.statut === DocStatus.CLASSE ? 'border-green-500/50' : 'border-brand shadow-brand/10'}`}
                    >
                        <div className="flex justify-between items-start mb-2">
                            <div className="flex-1">
                                <div className="flex items-center gap-2 mb-1">
                                    <ShieldAlert size={14} className={doc.statut === DocStatus.CLASSE ? 'text-green-500' : 'text-brand'} />
                                    <span className={`text-[11px] font-black uppercase ${doc.statut === DocStatus.CLASSE ? 'text-green-600' : 'text-brand'}`}>{doc.id}</span>
                                </div>
                                <h3 className="font-black text-slate-900 dark:text-gray-100 leading-tight uppercase tracking-tight line-clamp-1">{doc.victime_objet}</h3>
                                <p className="text-[10px] text-slate-500 font-bold mt-1 uppercase">{doc.lieu_date_heure}</p>
                            </div>
                            <div className="flex flex-col items-end">
                                {doc.rappel_actif ? <Bell size={18} className="text-brand animate-pulse" /> : <BellOff size={18} className="text-slate-300" />}
                            </div>
                        </div>

                        <p className="text-xs text-slate-600 dark:text-slate-400 line-clamp-2 mt-3 leading-relaxed border-t border-slate-100 dark:border-slate-800 pt-2">
                            {doc.description_sinistre}
                        </p>

                        <div className="flex items-center justify-between mt-5">
                             <div className="flex items-center gap-2">
                                <span className={`text-[9px] font-black px-3 py-1 rounded-full border ${doc.statut === DocStatus.CLASSE ? 'bg-green-50 text-green-600 border-green-200' : 'bg-orange-50 text-brand border-brand/20'}`}>
                                    {doc.statut.toUpperCase()}
                                </span>
                                {doc.aux_images && doc.aux_images.length > 0 && (
                                    <span className="bg-slate-100 text-slate-500 text-[9px] px-2 py-1 rounded-full flex items-center gap-1">
                                        <Paperclip size={10} /> {doc.aux_images.length}
                                    </span>
                                )}
                             </div>
                             <div className="flex gap-2">
                                <button onClick={e => handleDuplicate(doc, e)} className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-full text-blue-600 hover:scale-110 transition-transform" title="Dupliquer"><Copy size={16}/></button>
                                <button onClick={e => handleGeneratePDF(doc, e)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-600 hover:scale-110 transition-transform"><Printer size={16}/></button>
                                <button onClick={e => handleDelete(doc.id, e)} className="p-2 bg-red-50 dark:bg-red-900/20 rounded-full text-red-500 hover:scale-110 transition-transform"><Trash2 size={16}/></button>
                             </div>
                        </div>
                    </div>
                ))}
                {filteredDocs.length === 0 && (
                    <div className="flex flex-col items-center justify-center pt-24 text-slate-300 dark:text-slate-800">
                        <CheckCircle size={64} className="mb-4 opacity-20" />
                        <p className="font-black text-sm uppercase tracking-widest">Aucun avis archivé</p>
                    </div>
                )}
            </div>
        </div>
    );
};

{
  "name": "Avisapp",
  "description": "Assistant IA pour Avis d’Incident et Rapports d’Enquête",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum DocStatus {
  SUIVRE = "Suivre",
  CLASSER = "Classer"
}

export enum IncidentType {
  INCENDIE = "Incendie",
  DEGAT_EAUX = "Dégât des eaux",
  VANDALISME = "Vandalisme",
  ACCIDENT_TRAVAIL = "Accident de travail",
  PANNE_TECHNIQUE = "Panne technique",
  VOL_EFFRACTION = "Vol / Effraction",
  SINISTRE_ELECTRIQUE = "Sinistre électrique",
  AUTRE = "Autre"
}

export interface DocumentData {
  id: string; // Format: SRM-MS/DPH/AI-MMYYN
  document_image: string; 
  mimeType: string;
  aux_images: string[]; // Max 3 images pour causes et circonstances

  // Avis d'Incident (Page 1)
  victime_objet: string;
  description_sinistre: string;
  lieu_date_heure: string;
  dommages: string;
  causes_circonstances: string;
  responsabilites: string;
  mesures_prises: string;
  references_autorites: string;
