export type ScreenName = 'scanner' | 'dashboard' | 'stats' | 'settings';

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, IncidentType } from "../types";

const avisAppSchema = {
  type: Type.OBJECT,
  properties: {
    victime_objet: { type: Type.STRING },
    description_sinistre: { type: Type.STRING },
    lieu_date_heure: { type: Type.STRING },
    dommages: { type: Type.STRING },
    causes_circonstances: { type: Type.STRING },
    responsabilites: { type: Type.STRING },
    mesures_prises: { type: Type.STRING },
    references_autorites: { type: Type.STRING },
    observations: { type: Type.STRING },

    rapport_introduction: { type: Type.STRING },
    rapport_analyse_technique: { type: Type.STRING },
    rapport_analyse_causes: { type: Type.STRING },
    rapport_responsabilites: { type: Type.STRING },
    rapport_actions_correctives: { type: Type.STRING },
    rapport_recommandations: { type: Type.STRING },
    rapport_conclusion: { type: Type.STRING },

    nature_incident: { type: Type.STRING, enum: Object.values(IncidentType) },
    date_iso: { type: Type.STRING, description: "YYYY-MM-DD" }
  },
  required: ["victime_objet", "description_sinistre", "lieu_date_heure", "nature_incident", "date_iso"]
};

export const analyzeIncident = async (
  base64Data: string | null,
  mimeType: string | null,
  userNotes: string = ""
): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any = { parts: [] };

  if (base64Data && mimeType) {
    const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;
    contents.parts.push({ inlineData: { mimeType, data: cleanBase64 } });
  }

  const prompt = `
    RÔLE : Tu es un assistant administratif et technique spécialisé dans la rédaction d’Avis d’Incident et de Rapports d’Enquête SRM.
    COMPORTEMENT : Style neutre, factuel, français administratif clair. 
    RÈGLE D'OR : Ne jamais inventer d'information. Si une donnée est manquante, indique impérativement : « Non communiqué ».

    SOURCES : ${base64Data ? "Analyse le fichier joint" : "Utilise les notes textuelles"}. 
    NOTES UTILISATEUR : "${userNotes}"

    TACHE 1 : Remplir l'AVIS D'INCIDENT (9 rubriques).
    TACHE 2 : Générer le RAPPORT D’ENQUÊTE cohérent (7 sections).
    TACHE 3 : Identifier la date pour date_iso (YYYY-MM-DD).

    Respecte strictement les rubriques demandées dans le schéma de sortie.
  `;

  contents.parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: avisAppSchema,
        temperature: 0.1,
        systemInstruction: "Tu es un assistant administratif expert. Style neutre et factuel. Pas de supposition. Utilise 'Non communiqué' pour les manques."
      }
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert, Sparkles, AlertCircle } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || null);

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const generateSRMId = async (dateIso: string) => {
    const date = new Date(dateIso);
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = String(date.getFullYear()).slice(-2);
    const prefix = `SRM-MS/DPH/AI-${month}${year}`;

    const docs = await getAllDocuments();
    const monthlyDocs = docs.filter(d => d.id.startsWith(prefix));
    const counter = monthlyDocs.length + 1;
    return `${prefix}${counter}`;
  };

  const performAnalysis = async () => {
    if (!fileData && !userText.trim()) return;
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ ...prev, ...result }));
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData) return;
    setLoading(true);
    try {
      const dateIso = formData.date_iso || new Date().toISOString().split('T')[0];

      let srmId = formData.id;
      if (!srmId || srmId.startsWith('TEMP_')) {
        srmId = await generateSRMId(dateIso);
      }

      const isClassed = formData.statut === DocStatus.CLASSER;

      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: srmId,
        document_image: fileData || "",
        mimeType: mimeType || "",
        aux_images: auxImages,
        statut: formData.statut || DocStatus.SUIVRE,
        rappel_actif: !isClassed,
        created_at: initialData?.created_at || Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!formData && !analyzing) {
    return (
      <div className="flex flex-col h-full bg-white dark:bg-slate-950">
        <div className="p-6 space-y-6">
          <div className="text-center">
            <ShieldAlert size={48} className="text-brand mx-auto mb-2" />
            <h2 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Formulaire Scan</h2>
            <p className="text-xs text-slate-400 font-medium">Analyse combinée Image, PDF et Texte</p>
          </div>

          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Notes ou description libre</label>
              <textarea 
                className="w-full p-4 bg-slate-50 dark:bg-slate-900 rounded-2xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white"
                placeholder="Décrivez l'incident ici pour aider l'IA..."
                rows={5}
                value={userText}
                onChange={e => setUserText(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="relative group">
                <button onClick={() => cameraInputRef.current?.click()} className="w-full flex flex-col items-center bg-brand text-white p-6 rounded-3xl shadow-lg active:scale-95 transition-transform overflow-hidden relative">
                   <Camera size={28} />
                   <span className="text-[9px] font-black mt-2 uppercase tracking-widest">Prendre Photo</span>
                   {fileData && !mimeType.includes('pdf') && <div className="absolute inset-0 bg-brand/90 flex items-center justify-center"><AlertCircle size={20}/></div>}
                </button>
              </div>
              <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 p-6 rounded-3xl active:scale-95 transition-transform">
                <Upload size={28} />
                <span className="text-[9px] font-black mt-2 uppercase tracking-widest">Importer PDF</span>
                {mimeType.includes('pdf') && fileData && <div className="absolute inset-0 bg-slate-400/20 rounded-3xl" />}
              </button>
            </div>

            {fileData && (
              <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-900 p-3 rounded-xl border border-dashed border-slate-200 dark:border-slate-800">
                <FileText size={16} className="text-brand" />
                <span className="text-[10px] font-bold text-slate-500 truncate flex-1">Fichier prêt pour analyse</span>
                <button onClick={() => { setFileData(null); setMimeType(""); }}><X size={14} className="text-red-400" /></button>
              </div>
            )}

            <button 
              onClick={performAnalysis}
              disabled={!fileData && !userText.trim()}
              className="w-full bg-brand/10 text-brand border-2 border-brand py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 disabled:opacity-30 active:scale-95 transition-all"
            >
              <Wand2 size={18} /> LANCER L’ANALYSE
            </button>
          </div>
        </div>
        <button onClick={onCancel} className="mt-auto p-6 text-slate-400 font-bold text-xs uppercase tracking-widest text-center">Annuler</button>
        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
      </div>
    );
  }

  if (analyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 bg-white dark:bg-slate-950">
        <Loader2 size={48} className="text-brand animate-spin" />
        <p className="font-black text-brand uppercase tracking-widest animate-pulse">Traitement Administratif IA...</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 relative">
      <div className="flex-1 overflow-y-auto pb-32">
        <div className="p-4 space-y-6">
          <section className="space-y-3">
            <h4 className="text-xs font-black text-brand uppercase tracking-widest border-b-2 border-brand/10 pb-1">1. Avis d'Incident</h4>
            <Field label="Victime ou objet du sinistre" value={formData?.victime_objet} onChange={v => setFormData({...formData, victime_objet: v})} />
            <Field label="Description du sinistre" value={formData?.description_sinistre} onChange={v => setFormData({...formData, description_sinistre: v})} />
            <Field label="Lieu, date et heure du sinistre" value={formData?.lieu_date_heure} onChange={v => setFormData({...formData, lieu_date_heure: v})} />
            <Field label="Dommages (nature et évaluation)" value={formData?.dommages} onChange={v => setFormData({...formData, dommages: v})} />

            <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] font-black text-slate-400 uppercase">Causes et circonstances détaillées</label>
                <button onClick={() => auxInputRef.current?.click()} className="text-brand p-1"><Paperclip size={16}/></button>
              </div>
              <textarea 
                  className="w-full bg-transparent font-bold outline-none resize-none dark:text-white text-xs leading-relaxed mb-3" 
                  rows={4} 
                  value={formData?.causes_circonstances || ""} 
