import React, { useState } from 'react';
import { Database, Download, UploadCloud, Loader2, Moon, Sun, Bell } from 'lucide-react';
import { getAllDocuments, restoreBackup } from '../services/db';
import { DocumentData } from '../types';

interface SettingsProps {
    enableReminders: boolean;
    setEnableReminders: (val: boolean) => void;
    theme: 'light' | 'dark';
    setTheme: (t: 'light' | 'dark') => void;
}

export const Settings: React.FC<SettingsProps> = ({ enableReminders, setEnableReminders, theme, setTheme }) => {
    const [isRestoring, setIsRestoring] = useState(false);

    const handleBackup = async () => {
        try {
            const docs = await getAllDocuments();
            if (docs.length === 0) {
                alert("Aucune donnée à sauvegarder.");
                return;
            }
            const json = JSON.stringify(docs, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `avisapp_backup_${new Date().toISOString().split('T')[0]}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch (e) {
            console.error(e);
            alert("Erreur lors de la création de la sauvegarde.");
        }
    };

    const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!window.confirm(`Voulez-vous restaurer le fichier "${file.name}" ?\nAttention : Les données actuelles seront fusionnées.`)) {
            e.target.value = "";
            return;
        }

        setIsRestoring(true);
        const reader = new FileReader();

        reader.onload = async (event) => {
            try {
                const json = event.target?.result as string;
                if (!json) throw new Error("Fichier vide.");

                const data = JSON.parse(json);
                if (!Array.isArray(data)) throw new Error("Format invalide.");

                const count = await restoreBackup(data as DocumentData[]);
                alert(`${count} documents restaurés.`);
                window.location.reload();
            } catch (err: any) {
                console.error(err);
                alert("Erreur: " + err.message);
            } finally {
                setIsRestoring(false);
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="h-full bg-gray-50 dark:bg-slate-950 p-6 overflow-y-auto transition-colors duration-300">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white mb-8">Paramètres</h2>

            {isRestoring && (
                <div className="fixed inset-0 bg-black/60 z-[100] flex flex-col items-center justify-center text-white backdrop-blur-sm">
                    <Loader2 size={48} className="animate-spin mb-4 text-[#0ABAB5]" />
                    <p className="font-bold text-xl">Restauration en cours...</p>
                </div>
            )}

            {/* PREFERENCES SECTION */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-transparent dark:border-slate-800 p-6 space-y-6 mb-6 transition-colors duration-300">
                <div className="flex items-center space-x-2 text-[#FF6600]">
                    <Bell size={24} />
                    <h3 className="font-bold text-lg">Préférences</h3>
                </div>

                {/* Toggle Reminders */}
                <div className="flex items-center justify-between border-b border-gray-100 dark:border-slate-800 pb-4">
                    <span className="text-gray-700 dark:text-gray-200 text-sm font-medium">Activer les rappels visuels</span>
                    <div 
                        onClick={() => setEnableReminders(!enableReminders)}
                        className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors ${enableReminders ? 'bg-[#0ABAB5]' : 'bg-gray-300 dark:bg-gray-600'}`}
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform ${enableReminders ? 'translate-x-6' : ''}`}></div>
                    </div>
                </div>

                {/* Toggle Dark Mode */}
                <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-2">
                        {theme === 'dark' ? <Moon size={18} className="text-purple-400"/> : <Sun size={18} className="text-orange-400"/>}
                        <span className="text-gray-700 dark:text-gray-200 text-sm font-medium">Mode Sombre</span>
                    </div>
                    <div 
                        onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')}
                        className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors ${theme === 'dark' ? 'bg-purple-600' : 'bg-gray-300 dark:bg-gray-600'}`}
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform ${theme === 'dark' ? 'translate-x-6' : ''}`}></div>
                    </div>
                </div>
            </div>

            {/* DATA SECTION */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-transparent dark:border-slate-800 p-6 space-y-6 transition-colors duration-300">
                <div className="flex items-center space-x-2 text-gray-700 dark:text-gray-300">
                    <Database size={24} />
                    <h3 className="font-bold text-lg">Données</h3>
                </div>
                <p className="text-sm text-gray-600 dark:text-gray-400">
                    Gestion des sauvegardes locales (JSON).
                </p>

                <div className="grid grid-cols-1 gap-4">
                    <button 
                        onClick={handleBackup}
                        disabled={isRestoring}
                        className="w-full bg-gray-800 dark:bg-slate-700 text-white font-bold py-3 rounded-xl shadow-md active:scale-95 transition-transform flex justify-center items-center space-x-2"
                    >
                        <Download size={18} />
                        <span>Sauvegarder mes données</span>
                    </button>

                    <label className={`w-full bg-white dark:bg-slate-800 border-2 border-gray-200 dark:border-slate-700 text-gray-700 dark:text-gray-300 font-bold py-3 rounded-xl hover:bg-gray-50 dark:hover:bg-slate-700 active:scale-95 transition-transform flex justify-center items-center space-x-2 cursor-pointer ${isRestoring ? 'opacity-50' : ''}`}>
                        <UploadCloud size={18} />
                        <span>Restaurer une sauvegarde</span>
                        <input 
                            type="file" 
                            accept=".json"
                            className="hidden"
                            onChange={handleRestore}
                            disabled={isRestoring}
                        />
                    </label>
                </div>
            </div>

            <div className="mt-8 text-center pb-6">
                <p className="text-xs text-gray-400 dark:text-gray-600 font-mono">Avisapp AI v1.2.0</p>
            </div>
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { Search, Filter, Download, Trash2, Printer, Loader2, ShieldAlert, CheckCircle, Copy, Bell, BellOff, Paperclip, FileText, Wand2, Edit3, X, BellRing } from 'lucide-react';
import { DocumentData, DocStatus } from '../types';
import { getAllDocuments, deleteDocument } from '../services/db';
import * as XLSX from 'xlsx';
import { jsPDF } from "jspdf";

interface DashboardProps {
    onEdit: (doc: DocumentData, triggerAI?: boolean) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onEdit }) => {
    const [documents, setDocuments] = useState<DocumentData[]>([]);
    const [filteredDocs, setFilteredDocs] = useState<DocumentData[]>([]);
    const [search, setSearch] = useState("");
    const [filterStatus, setFilterStatus] = useState<"ALL" | DocStatus>("ALL");
    const [generatingPdf, setGeneratingPdf] = useState(false);
    const [duplicatingDoc, setDuplicatingDoc] = useState<DocumentData | null>(null);

    useEffect(() => { loadData(); }, []);

    useEffect(() => {
        let res = documents;
        if (search) {
            const lower = search.toLowerCase();
            res = res.filter(d => 
                d.id.toLowerCase().includes(lower) || 
                d.victime_objet.toLowerCase().includes(lower) ||
                d.description_sinistre.toLowerCase().includes(lower)
            );
        }
        if (filterStatus !== "ALL") res = res.filter(d => d.statut === filterStatus);
        setFilteredDocs(res);
    }, [search, filterStatus, documents]);

    const loadData = async () => setDocuments(await getAllDocuments());

    const handleDuplicateClick = (doc: DocumentData, e: React.MouseEvent) => {
        e.stopPropagation();
        setDuplicatingDoc(doc);
    };

    const confirmDuplicate = (mode: 'MANUAL' | 'IA') => {
        if (!duplicatingDoc) return;
        const newDoc = { 
            ...duplicatingDoc, 
            id: `TEMP_${Date.now()}`, 
            created_at: Date.now(),
            statut: DocStatus.SUIVRE,
            rappel_actif: true
        };
        onEdit(newDoc, mode === 'IA');
        setDuplicatingDoc(null);
    };

    const handleGeneratePDF = async (doc: DocumentData, e: React.MouseEvent) => {
        e.stopPropagation();
        setGeneratingPdf(true);
        try {
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pageWidth = pdf.internal.pageSize.getWidth();
            const margin = 12;

            // --- ESPACE POUR PAPIER PRE-IMPRIME ---
            // On commence plus bas pour laisser de la place à l'en-tête officiel (55mm)
            let currentY = 55; 

            // --- PAGE 1: AVIS D'INCIDENT (TABULAIRE) ---
            pdf.setFontSize(14);
            pdf.setFont("helvetica", "bold");
            pdf.setTextColor(0, 0, 0);
            pdf.text("MONSIEUR LE DIRECTEUR GÉNÉRAL", pageWidth / 2, currentY, { align: "center" });
            currentY += 8;
            pdf.text(`AVIS D'INCIDENT N°: ${doc.id}`, pageWidth / 2, currentY, { align: "center" });
            currentY += 12;

            const rubrics = [
                { label: "1-Victime ou objet du sinistre", value: doc.victime_objet },
                { label: "2-Description du sinistre", value: doc.description_sinistre },
                { label: "3-Lieu, date et heure du sinistre", value: doc.lieu_date_heure },
                { label: "4-Dommages (nature et évaluation sommaire)", value: doc.dommages },
                { label: "5-Causes et circonstances détaillées", value: doc.causes_circonstances },
                { label: "6-Responsabilités", value: doc.responsabilites },
                { label: "7-Mesures prises pour la limitation ou réparation", value: doc.mesures_prises },
                { label: "8-Références (autorités, dépôt de plainte)", value: doc.references_autorites },
                { label: "9-Observations", value: doc.observations }
            ];

            const col1Width = 55;
            const col2Width = pageWidth - 2 * margin - col1Width;
            pdf.setFontSize(9);

            rubrics.forEach(rubric => {
                const textLines = pdf.splitTextToSize(rubric.value || "Non communiqué", col2Width - 4);
                const labelLines = pdf.splitTextToSize(rubric.label, col1Width - 4);
                const cellHeight = Math.max(12, Math.max(textLines.length, labelLines.length) * 5 + 4);

                if (currentY + cellHeight > 275) { pdf.addPage(); currentY = 15; }

                pdf.setDrawColor(180);
                pdf.rect(margin, currentY, col1Width, cellHeight);
                pdf.rect(margin + col1Width, currentY, col2Width, cellHeight);

                pdf.setFont("helvetica", "bold");
                pdf.text(labelLines, margin + 2, currentY + 6);
                pdf.setFont("helvetica", "normal");
                pdf.text(textLines, margin + col1Width + 2, currentY + 6);
                currentY += cellHeight;
            });

            currentY += 15;
            pdf.setFontSize(10);

            // --- CENTRAGE DE LA MENTION FAIT A ... LE ... ---
            const signaturePlaceDate = `Fait à : ${doc.fait_a || '....................'}    Le : ${doc.fait_le || '....................'}`;
            pdf.setFont("helvetica", "bold");
            pdf.text(signaturePlaceDate, pageWidth / 2, currentY, { align: "center" });

            currentY += 15;
            pdf.text("Signature du Chef de l'entité", margin + 15, currentY);
            pdf.text("Signature du Chef de Division", pageWidth - margin - 65, currentY);

            // --- PAGE 2: RAPPORT D'ENQUÊTE ---
            pdf.addPage();
            currentY = 20;
            pdf.setFontSize(16);
            pdf.setFont("helvetica", "bold");
            pdf.text("RAPPORT D'ENQUÊTE", pageWidth / 2, currentY, { align: "center" });
            currentY += 15;

            const sections = [
                { t: "Introduction", c: doc.rapport_introduction },
                { t: "Analyse technique", c: doc.rapport_analyse_technique },
                { t: "Analyse des causes", c: doc.rapport_analyse_causes },
                { t: "Responsabilités", c: doc.rapport_responsabilites },
                { t: "Actions correctives", c: doc.rapport_actions_correctives },
                { t: "Recommandations", c: doc.rapport_recommandations },
                { t: "Conclusion", c: doc.rapport_conclusion }
            ];

            sections.forEach(s => {
                pdf.setFontSize(11);
                pdf.setFont("helvetica", "bold");
                pdf.text(s.t, margin, currentY);
                currentY += 6;
                pdf.setFont("helvetica", "normal");
                pdf.setFontSize(10);
                const lines = pdf.splitTextToSize(s.c || "Non communiqué", pageWidth - 2 * margin);
                pdf.text(lines, margin, currentY);
                currentY += lines.length * 5 + 8;
                if (currentY > 270) { pdf.addPage(); currentY = 20; }
            });

            // --- ANNEXES ---
            const allImgs = [doc.document_image, ...(doc.aux_images || [])].filter(i => i && i.length > 500);
            if (allImgs.length > 0) {
                pdf.addPage();
                currentY = 20;
                pdf.setFontSize(14);
                pdf.setFont("helvetica", "bold");
                pdf.text("ANNEXES PHOTOGRAPHIQUES", pageWidth / 2, currentY, { align: "center" });
                currentY += 15;

                let imgCount = 0;
                allImgs.forEach(img => {
                    if (imgCount === 3) { pdf.addPage(); currentY = 20; imgCount = 0; }
                    try {
                        pdf.addImage(img, 'JPEG', margin + 15, currentY, pageWidth - 2 * margin - 30, 75);
                        currentY += 85;
                        imgCount++;
                    } catch(e) {}
                });
            }

            pdf.save(`Dossier_Avisapp_${doc.id.replace(/\//g, '-')}.pdf`);
        } catch (err) {
            console.error(err);
            alert("Erreur de génération PDF.");
        } finally {
            setGeneratingPdf(false);
        }
    };

    const handleDelete = async (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirm("Supprimer ce dossier SRM ?")) {
            await deleteDocument(id);
            loadData();
        }
    };

    return (
        <div className="h-full bg-slate-50 dark:bg-slate-950 flex flex-col relative overflow-hidden">
            {generatingPdf && (
                <div className="fixed inset-0 bg-black/80 z-[100] flex flex-col items-center justify-center text-white backdrop-blur-md">
