export type ScreenName = 'scanner' | 'dashboard' | 'stats' | 'settings';

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert, Sparkles, BellRing, MapPin, Calendar, Hash } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [generatedId, setGeneratedId] = useState<string>(initialData?.id || "");

  // Initialisation avec valeurs par défaut
  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || {
    fait_a: "Tahannaout",
    fait_le: new Date().toLocaleDateString('fr-FR'),
    statut: DocStatus.SUIVRE,
    nature_incident: IncidentType.AUTRE,
    date_iso: new Date().toISOString().split('T')[0]
  });

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  // Gérer la numérotation automatique lors de la saisie d'un nouveau document
  useEffect(() => {
    if (!initialData) {
      updateAutomaticId();
    }
  }, [formData?.date_iso]);

  const updateAutomaticId = async () => {
    const dateStr = formData?.date_iso || new Date().toISOString().split('T')[0];
    const id = await calculateNextSRMId(dateStr);
    setGeneratedId(id);
  };

  const calculateNextSRMId = async (dateIso: string) => {
    const date = new Date(dateIso);
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = String(date.getFullYear()).slice(-2);
    const mmYY = `${month}${year}`;
    const prefix = `SRM-MS/DPH/AI-${mmYY}`;

    const docs = await getAllDocuments();
    // Filtrer les documents qui ont le même préfixe MMYY
    const monthlyDocs = docs.filter(d => d.id.startsWith(prefix));

    // Trouver le numéro le plus élevé
    let maxCounter = 0;
    monthlyDocs.forEach(d => {
      const counterStr = d.id.replace(prefix, "");
      const counter = parseInt(counterStr, 10);
      if (!isNaN(counter) && counter > maxCounter) {
        maxCounter = counter;
      }
    });

    return `${prefix}${maxCounter + 1}`;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const performAnalysis = async () => {
    if (!fileData && !userText.trim()) return;
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ 
        ...prev, 
        ...result,
        fait_a: prev?.fait_a || "Tahannaout",
        fait_le: prev?.fait_le || new Date().toLocaleDateString('fr-FR'),
        date_iso: result.date_iso || prev?.date_iso
      }));
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData) return;
    setLoading(true);
    try {
      const finalId = initialData ? initialData.id : generatedId;
      const isClassed = formData.statut === DocStatus.CLASSER;

      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: finalId,
        document_image: fileData || "",
        mimeType: mimeType || "",
        aux_images: auxImages,
        statut: formData.statut || DocStatus.SUIVRE,
        rappel_actif: !isClassed,
        rappel_details: formData.rappel_details || "",
        fait_a: formData.fait_a || "Tahannaout",
        fait_le: formData.fait_le || new Date().toLocaleDateString('fr-FR'),
        created_at: initialData?.created_at || Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!formData && !analyzing) {
    return (
      <div className="flex flex-col h-full bg-white dark:bg-slate-950 p-6 overflow-y-auto">
        <div className="flex flex-col items-center mb-6">
          <ShieldAlert size={48} className="text-brand mb-2" />
          <h2 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Formulaire Scan</h2>
          <p className="text-xs text-slate-400 font-medium">Assistant Avisapp Administratif</p>
        </div>

        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Description libre (Texte)</label>
            <textarea 
              className="w-full p-4 bg-slate-50 dark:bg-slate-900 rounded-2xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white"
              placeholder="Saisissez des détails bruts pour l'IA..."
              rows={4}
              value={userText}
              onChange={e => setUserText(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => cameraInputRef.current?.click()} className="flex flex-col items-center bg-brand text-white p-6 rounded-3xl shadow-lg active:scale-95 transition-transform">
               <Camera size={28} />
               <span className="text-[9px] font-black mt-2 uppercase tracking-widest">Photo</span>
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center bg-blue-600 text-white p-6 rounded-3xl shadow-lg active:scale-95 transition-transform">
              <Upload size={28} />
              <span className="text-[9px] font-black mt-2 uppercase tracking-widest">PDF / Image</span>
            </button>
          </div>

          {fileData && (
            <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-900 p-3 rounded-xl border border-dashed border-slate-200 dark:border-slate-800">
              <FileText size={16} className="text-brand" />
              <span className="text-[10px] font-bold text-slate-500 truncate flex-1">{mimeType.includes('pdf') ? 'PDF Importé' : 'Image sélectionnée'}</span>
              <button onClick={() => { setFileData(null); setMimeType(""); }}><X size={14} className="text-red-400" /></button>
            </div>
          )}

          <button 
            onClick={performAnalysis}
            disabled={!fileData && !userText.trim()}
            className="w-full bg-brand/10 text-brand border-2 border-brand py-4 rounded-2xl font-black text-sm flex items-center justify-center gap-2 disabled:opacity-30 active:scale-95 transition-all"
          >
            <Wand2 size={18} /> LANCER L’ANALYSE
          </button>
        </div>
        <button onClick={onCancel} className="mt-8 text-slate-400 font-bold text-xs uppercase tracking-widest text-center">Annuler</button>
        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
      </div>
    );
  }

  if (analyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 bg-white dark:bg-slate-950">
        <Loader2 size={48} className="text-brand animate-spin" />
        <p className="font-black text-brand uppercase tracking-widest animate-pulse">Réorganisation Administrative...</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 relative">
      <div className="flex-1 overflow-y-auto pb-36">
        <div className="p-4 space-y-8">
          <section className="space-y-3">
            <div className="flex justify-between items-center border-b-2 border-brand/10 pb-1">
              <h4 className="text-xs font-black text-brand uppercase tracking-widest flex items-center gap-2">
                <Hash size={14} /> ID: {generatedId}
              </h4>
              <button onClick={performAnalysis} title="Réorganiser avec l'IA" className="text-brand/50 hover:text-brand"><Sparkles size={16}/></button>
            </div>

            <Field label="Victime ou objet du sinistre" value={formData?.victime_objet} onChange={v => setFormData({...formData, victime_objet: v})} />
            <Field label="Description du sinistre" value={formData?.description_sinistre} onChange={v => setFormData({...formData, description_sinistre: v})} />
            <Field label="Lieu, date et heure du sinistre" value={formData?.lieu_date_heure} onChange={v => setFormData({...formData, lieu_date_heure: v})} />
            <Field label="Dommages (nature et évaluation)" value={formData?.dommages} onChange={v => setFormData({...formData, dommages: v})} />

            <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] font-black text-slate-400 uppercase">Causes et circonstances détaillées</label>
                <button onClick={() => auxInputRef.current?.click()} className="text-brand/70 hover:text-brand transition-colors"><Paperclip size={18}/></button>
              </div>
              <textarea 
                  className="w-full bg-transparent font-bold outline-none resize-none dark:text-white text-xs leading-relaxed mb-3" 
                  rows={4} 
                  value={formData?.causes_circonstances || ""} 
                  onChange={e => setFormData({...formData, causes_circonstances: e.target.value})} 
              />
              <div className="flex gap-2 overflow-x-auto pb-1">
                {auxImages.map((img, i) => (
                  <div key={i} className="relative w-20 h-20 rounded-xl overflow-hidden border-2 border-brand shrink-0 group">
                    <img src={img} className="w-full h-full object-cover" />
                    <button onClick={() => setAuxImages(auxImages.filter((_, idx) => idx !== i))} className="absolute top-0 right-0 bg-red-500 text-white p-1 rounded-bl-lg shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"><X size={12}/></button>
                  </div>
                ))}
                {auxImages.length < 3 && auxImages.length > 0 && (
                  <button onClick={() => auxInputRef.current?.click()} className="w-20 h-20 rounded-xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex items-center justify-center text-slate-300"><Paperclip size={20}/></button>
                )}
              </div>
              <input type="file" accept="image/*" className="hidden" ref={auxInputRef} onChange={handleAuxImage} />
            </div>

            <Field label="Responsabilités" value={formData?.responsabilites} onChange={v => setFormData({...formData, responsabilites: v})} />
            <Field label="Mesures prises" value={formData?.mesures_prises} onChange={v => setFormData({...formData, mesures_prises: v})} />
            <Field label="Références (autorités, plainte)" value={formData?.references_autorites} onChange={v => setFormData({...formData, references_autorites: v})} />
            <Field label="Observations" value={formData?.observations} onChange={v => setFormData({...formData, observations: v})} />

            <div className="grid grid-cols-2 gap-4">
               <Field icon={<MapPin size={12}/>} label="Fait à :" value={formData?.fait_a} onChange={v => setFormData({...formData, fait_a: v})} />
               <Field icon={<Calendar size={12}/>} label="Le :" value={formData?.fait_le} onChange={v => setFormData({...formData, fait_le: v})} />
            </div>
          </section>

          <section className="space-y-3">
            <h4 className="text-xs font-black text-brand uppercase tracking-widest border-b-2 border-brand/10 pb-1">2. RAPPORT D'ENQUÊTE</h4>
            <Field label="Introduction" value={formData?.rapport_introduction} isTextarea onChange={v => setFormData({...formData, rapport_introduction: v})} />
            <Field label="Analyse technique" value={formData?.rapport_analyse_technique} isTextarea onChange={v => setFormData({...formData, rapport_analyse_technique: v})} />
            <Field label="Analyse des causes" value={formData?.rapport_analyse_causes} isTextarea onChange={v => setFormData({...formData, rapport_analyse_causes: v})} />
            <Field label="Actions correctives" value={formData?.rapport_actions_correctives} isTextarea onChange={v => setFormData({...formData, rapport_actions_correctives: v})} />
            <Field label="Recommandations" value={formData?.rapport_recommandations} isTextarea onChange={v => setFormData({...formData, rapport_recommandations: v})} />
            <Field label="Conclusion" value={formData?.rapport_conclusion} isTextarea onChange={v => setFormData({...formData, rapport_conclusion: v})} />
          </section>

          <section className="grid grid-cols-2 gap-4">
            <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Nature de l'incident</label>
              <select className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" value={formData?.nature_incident} onChange={e => setFormData({...formData, nature_incident: e.target.value as IncidentType})}>
                  {Object.values(IncidentType).map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Dossier</label>
              <select 
                className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" 
                value={formData?.statut} 
                onChange={e => {
                  const newStatus = e.target.value as DocStatus;
                  setFormData({...formData, statut: newStatus, rappel_actif: newStatus !== DocStatus.CLASSER});
                }}
              >
                  <option value={DocStatus.SUIVRE}>SUIVRE</option>
                  <option value={DocStatus.CLASSER}>CLASSER</option>
              </select>
            </div>
          </section>

          {/* Champ de Rappel */}
          <section className="space-y-3 pb-8">
            <h4 className="text-xs font-black text-brand uppercase tracking-widest border-b-2 border-brand/10 pb-1 flex items-center gap-2">
              <BellRing size={14} /> 3. SUIVI & RAPPEL
            </h4>
            <div className={`bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800 transition-opacity ${formData?.statut === DocStatus.CLASSER ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Note ou date de rappel</label>
                <textarea 
                  className="w-full bg-transparent font-bold outline-none dark:text-white text-xs leading-relaxed" 
                  rows={2} 
                  placeholder="Ex: Relancer le service technique le 15..."
                  value={formData?.rappel_details || ""} 
                  onChange={e => setFormData({...formData, rappel_details: e.target.value})} 
                />
            </div>
          </section>
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-50 dark:from-slate-950 via-slate-50 dark:via-slate-950 to-transparent pt-10 flex gap-2 z-30">
        <button onClick={() => { setFormData(null); setFileData(null); setUserText(""); }} className="bg-slate-200 dark:bg-slate-800 p-5 rounded-3xl text-slate-500 active:scale-90 transition-transform"><RefreshCw size={24}/></button>
        <button onClick={handleSave} disabled={loading} className="flex-1 bg-brand text-white py-5 rounded-3xl font-black text-xl shadow-xl flex items-center justify-center gap-3 active:scale-95 transition-transform">
          {loading ? <Loader2 className="animate-spin" /> : <Save />} ENREGISTRER
        </button>
      </div>
    </div>
  );
};

const Field = ({ label, value, onChange, isTextarea, icon }: any) => (
  <div className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-200 dark:border-slate-800 focus-within:border-brand transition-all flex flex-col">
    <div className="flex items-center gap-1.5 mb-1">
      {icon && <span className="text-slate-400">{icon}</span>}
      <label className="block text-[10px] font-black text-slate-400 uppercase">{label}</label>
    </div>
    {isTextarea ? (
      <textarea className="w-full bg-transparent font-bold outline-none dark:text-white text-xs leading-relaxed" rows={3} value={value || ""} onChange={e => onChange(e.target.value)} />
    ) : (
      <input className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" value={value || ""} onChange={e => onChange(e.target.value)} />
    )}
  </div>
);

export enum DocStatus {
  SUIVRE = "Suivre",
  CLASSER = "Classer"
}

export enum IncidentType {
  INCENDIE = "Incendie",
  DEGAT_EAUX = "Dégât des eaux",
  VANDALISME = "Vandalisme",
  ACCIDENT_TRAVAIL = "Accident de travail",
  PANNE_TECHNIQUE = "Panne technique",
  VOL_EFFRACTION = "Vol / Effraction",
  SINISTRE_ELECTRIQUE = "Sinistre électrique",
  RESEAU_ELECTRIQUE = "Réseau Électrique",
  TIERS = "Tiers",
  AUTRE = "Autre"
}

export interface DocumentData {
  id: string; // Format: SRM-MS/DPH/AI-MMYYN
  document_image: string; 
  mimeType: string;
  aux_images: string[]; // Max 3 images liées aux causes et circonstances

  // Avis d'Incident (Page 1)
  victime_objet: string;
  description_sinistre: string;
  lieu_date_heure: string;
