import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, IncidentType } from "../types";

const avisAppSchema = {
  type: Type.OBJECT,
  properties: {
    victime_objet: { type: Type.STRING },
    description_sinistre: { type: Type.STRING },
    lieu_date_heure: { type: Type.STRING },
    dommages: { type: Type.STRING },
    causes_circonstances: { type: Type.STRING },
    responsabilites: { type: Type.STRING },
    mesures_prises: { type: Type.STRING },
    references_autorites: { type: Type.STRING },
    observations: { type: Type.STRING },
    fait_a: { type: Type.STRING },
    fait_le: { type: Type.STRING },

    rapport_introduction: { type: Type.STRING },
    rapport_analyse_technique: { type: Type.STRING },
    rapport_analyse_causes: { type: Type.STRING },
    rapport_responsabilites: { type: Type.STRING },
    rapport_actions_correctives: { type: Type.STRING },
    rapport_recommandations: { type: Type.STRING },
    rapport_conclusion: { type: Type.STRING },

    nature_incident: { type: Type.STRING, enum: Object.values(IncidentType) },
    date_iso: { type: Type.STRING, description: "Date au format YYYY-MM-DD identifiée dans le contenu" }
  },
  required: ["victime_objet", "description_sinistre", "lieu_date_heure", "nature_incident", "date_iso"]
};

export const analyzeIncident = async (
  base64Data: string | null,
  mimeType: string | null,
  userNotes: string = ""
): Promise<Partial<DocumentData>> => {
  // Fixed: Exclusively use process.env.API_KEY as per the guidelines.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any = { parts: [] };

  if (base64Data && mimeType) {
    const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;
    contents.parts.push({ inlineData: { mimeType, data: cleanBase64 } });
  }

  const prompt = `
    RÔLE : Tu es un assistant administratif et technique expert en rédaction d'Avis d'Incident et de Rapports d'Enquête.
    TON : Français administratif clair, neutre, structuré et factuel. Sans émotion ni jugement.

    INSTRUCTIONS CRITIQUES :
    - Ne jamais inventer de faits, dates, lieux ou noms.
    - Toute information manquante doit être indiquée par : « Non communiqué ».
    - Combine l'analyse visuelle (image/PDF joint) avec les notes utilisateur : "${userNotes}".

    STRUCTURE ATTENDUE :
    1. AVIS D'INCIDENT (9 rubriques).
    2. SIGNATURE : Essaye d'extraire le lieu ("fait_a") et la date ("fait_le") de signature si présents.
    3. RAPPORT D'ENQUÊTE (Introduction, Analyses, Responsabilités, Actions, Recommandations, Conclusion).
    4. DATE_ISO : Extraire la date précise de l'incident (YYYY-MM-DD).

    Respecte strictement le schéma JSON de sortie.
  `;

  contents.parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: avisAppSchema,
        temperature: 0.1,
        systemInstruction: "Tu es l'assistant Avisapp. Rédige de façon administrative. Indique 'Non communiqué' pour tout manque. Pas de Markdown."
      }
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA.");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Database, Download, UploadCloud, Loader2, Moon, Sun, Bell } from 'lucide-react';
import { getAllDocuments, restoreBackup } from '../services/db';
import { DocumentData } from '../types';

interface SettingsProps {
    enableReminders: boolean;
    setEnableReminders: (val: boolean) => void;
    theme: 'light' | 'dark';
    setTheme: (t: 'light' | 'dark') => void;
}

export const Settings: React.FC<SettingsProps> = ({ enableReminders, setEnableReminders, theme, setTheme }) => {
    const [isRestoring, setIsRestoring] = useState(false);

    const handleBackup = async () => {
        try {
            const docs = await getAllDocuments();
            if (docs.length === 0) {
                alert("Aucune donnée à sauvegarder.");
                return;
            }
            const json = JSON.stringify(docs, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `avisapp_backup_${new Date().toISOString().split('T')[0]}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch (e) {
            console.error(e);
            alert("Erreur lors de la création de la sauvegarde.");
        }
    };

    const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!window.confirm(`Voulez-vous restaurer le fichier "${file.name}" ?\nAttention : Les données actuelles seront fusionnées.`)) {
            e.target.value = "";
            return;
        }

        setIsRestoring(true);
        const reader = new FileReader();

        reader.onload = async (event) => {
            try {
                const json = event.target?.result as string;
                if (!json) throw new Error("Fichier vide.");

                const data = JSON.parse(json);
                if (!Array.isArray(data)) throw new Error("Format invalide.");

                const count = await restoreBackup(data as DocumentData[]);
                alert(`${count} documents restaurés.`);
                window.location.reload();
            } catch (err: any) {
                console.error(err);
                alert("Erreur: " + err.message);
            } finally {
                setIsRestoring(false);
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="h-full bg-gray-50 dark:bg-slate-950 p-6 overflow-y-auto transition-colors duration-300">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white mb-8">Paramètres</h2>

            {isRestoring && (
