// Définition globale pour l'interface aistudio fournie par la plateforme
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export const Settings: React.FC<SettingsProps> = ({ enableReminders, setEnableReminders, theme, setTheme }) => {
    const [isRestoring, setIsRestoring] = useState(false);
    const [hasApiKey, setHasApiKey] = useState(false);

    useEffect(() => {
        checkApiKeyStatus();
    }, []);

    const checkApiKeyStatus = async () => {
        if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
            const status = await window.aistudio.hasSelectedApiKey();
            setHasApiKey(status);
        }
    };

    const handleSelectKey = async () => {
        if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
            try {
                await window.aistudio.openSelectKey();
                // On assume le succès selon les consignes de race condition
                setHasApiKey(true);
            } catch (err) {
                console.error("Erreur lors de la sélection de la clé", err);
            }
        }
    };

    const handleBackup = async () => {
        try {
            const docs = await getAllDocuments();
            if (docs.length === 0) {
                alert("Aucune donnée à sauvegarder.");
                return;
            }
            const json = JSON.stringify(docs, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `avisapp_backup_${new Date().toISOString().split('T')[0]}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch (e) {
            console.error(e);
            alert("Erreur lors de la création de la sauvegarde.");
        }
    };

    const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!window.confirm(`Voulez-vous restaurer le fichier "${file.name}" ?\nAttention : Les données actuelles seront fusionnées.`)) {
            e.target.value = "";
            return;
        }

        setIsRestoring(true);
        const reader = new FileReader();

        reader.onload = async (event) => {
            try {
                const json = event.target?.result as string;
                if (!json) throw new Error("Fichier vide.");

                const data = JSON.parse(json);
                if (!Array.isArray(data)) throw new Error("Format invalide.");

                const count = await restoreBackup(data as DocumentData[]);
                alert(`${count} documents restaurés.`);
                window.location.reload();
            } catch (err: any) {
                console.error(err);
                alert("Erreur: " + err.message);
            } finally {
                setIsRestoring(false);
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="h-full bg-slate-50 dark:bg-slate-950 p-6 overflow-y-auto transition-colors duration-300">
            <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-8 tracking-tight">Paramètres</h2>

            {isRestoring && (
                <div className="fixed inset-0 bg-black/60 z-[100] flex flex-col items-center justify-center text-white backdrop-blur-sm">
                    <Loader2 size={48} className="animate-spin mb-4 text-[#0ABAB5]" />
                    <p className="font-bold text-xl uppercase tracking-widest">Restauration...</p>
                </div>
            )}

            {/* SECTION IA - DESIGN FIDÈLE À L'IMAGE */}
            <div className="bg-[#020617] rounded-[2.5rem] border border-slate-800 p-8 mb-8 shadow-2xl overflow-hidden relative">
                <div className="flex items-start justify-between mb-8">
                    <div className="flex items-center gap-4">
                        <div className="bg-slate-900/50 p-3 rounded-2xl border border-slate-800">
                            <Lock className="text-[#0ABAB5]" size={28} />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-[#0ABAB5] uppercase tracking-tighter leading-none">Intelligence</h3>
                            <h3 className="text-xl font-black text-[#0ABAB5] uppercase tracking-tighter leading-none mt-1">Artificielle</h3>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 bg-[#061a1a] border border-[#0abab5]/20 px-4 py-2 rounded-full">
                        <ShieldCheck size={14} className="text-[#0ABAB5]" />
                        <span className="text-[9px] font-black text-[#0ABAB5] uppercase tracking-widest leading-none">Optimisé Gratuit</span>
                    </div>
                </div>

                <div className="bg-[#040d1e] rounded-3xl p-6 border border-slate-800 mb-8">
                    <div className="flex gap-4">
                        <div className="shrink-0 pt-1">
                            <Lightbulb size={20} className="text-yellow-400" />
                        </div>
                        <p className="text-sm text-slate-400 font-medium leading-relaxed">
                            Pour utiliser Avisapp AI gratuitement, créez une clé API gratuite sur <span className="text-slate-200 font-bold">Google AI Studio</span>. Aucun frais n'est appliqué pour une utilisation standard.
                        </p>
                    </div>
                    <a 
                        href="https://aistudio.google.com/app/apikey" 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center justify-center gap-2 mt-6 text-[#0ABAB5] font-black text-xs uppercase tracking-widest hover:underline"
                    >
                        Obtenir ma clé gratuite <ExternalLink size={14} />
