                <div className="space-y-6">
                    <div>
                        <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 ml-2">Votre clé API Gemini</label>
                        <div className="bg-[#0c162d] border border-slate-800 rounded-2xl p-5 flex items-center justify-between group cursor-pointer" onClick={handleSelectKey}>
