            {/* PREFERENCES SECTION */}
            <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 p-8 space-y-6 mb-6 transition-all">
                <div className="flex items-center space-x-2 text-brand">
                    <Bell size={24} />
                    <h3 className="font-black text-lg uppercase tracking-tight">Préférences</h3>
                </div>

                <div className="flex items-center justify-between border-b border-slate-50 dark:border-slate-800 pb-4">
                    <span className="text-slate-700 dark:text-slate-200 text-sm font-bold">Activer les rappels visuels</span>
                    <button 
                        onClick={() => setEnableReminders(!enableReminders)}
                        className={`w-14 h-7 rounded-full p-1 transition-colors duration-300 ${enableReminders ? 'bg-brand' : 'bg-slate-200 dark:bg-slate-700'}`}
                    >
                        <div className={`w-5 h-5 bg-white rounded-full shadow-lg transform transition-transform duration-300 ${enableReminders ? 'translate-x-7' : ''}`}></div>
                    </button>
                </div>

                <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-2">
                        {theme === 'dark' ? <Moon size={18} className="text-purple-400"/> : <Sun size={18} className="text-orange-400"/>}
                        <span className="text-slate-700 dark:text-slate-200 text-sm font-bold">Mode Sombre</span>
