import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert, Sparkles, BellRing, MapPin, Calendar, Hash, Tag, Clock } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);

  const [showForm, setShowForm] = useState(!!initialData);

  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || {
    id: "Génération...",
    fait_a: "Tahannaout",
    fait_le: new Date().toLocaleDateString('fr-FR'),
    statut: DocStatus.SUIVRE,
    nature_incident: IncidentType.AUTRE,
    date_iso: new Date().toISOString().split('T')[0],
    rappel_details: ""
  });

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const isNewOrDuplicate = !initialData || !initialData.id || initialData.id === "" || initialData.id.startsWith("TEMP_");
    if (isNewOrDuplicate && showForm) {
      updateAutomaticId();
    }
  }, [formData?.date_iso, showForm]);

  const updateAutomaticId = async () => {
    const dateStr = formData?.date_iso || new Date().toISOString().split('T')[0];
    const nextId = await calculateNextSRMId(dateStr);
    setFormData(prev => prev ? { ...prev, id: nextId } : null);
  };

  const calculateNextSRMId = async (dateIso: string) => {
    try {
      let date = new Date(dateIso);
      if (isNaN(date.getTime())) date = new Date();

      const month = String(date.getMonth() + 1).padStart(2, '0');
      const year = String(date.getFullYear()).slice(-2);
      const mmYY = `${month}${year}`;
      const prefix = `SRM-MS/DPH/AI-${mmYY}`;

      const docs = await getAllDocuments();
      const monthlyDocs = docs.filter(d => d.id && d.id.startsWith(prefix));

      let maxN = 0;
      monthlyDocs.forEach(doc => {
        const nPart = doc.id.substring(prefix.length);
        const n = parseInt(nPart, 10);
        if (!isNaN(n) && n > maxN) maxN = n;
      });

      return `${prefix}${maxN + 1}`;
    } catch (e) {
      console.error("Erreur calcul ID", e);
      return `SRM-MS/DPH/AI-${new Date().getTime()}`;
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const performAnalysis = async () => {
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ 
        ...prev, 
        ...result,
        id: prev?.id && prev.id !== "Génération..." ? prev.id : "Génération...",
        fait_a: prev?.fait_a || "Tahannaout",
        fait_le: prev?.fait_le || new Date().toLocaleDateString('fr-FR'),
        date_iso: result.date_iso || prev?.date_iso
      }));
      setShowForm(true);
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
      setShowForm(true); 
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !formData.id || formData.id === "Génération...") {
       alert("Le numéro d'avis n'a pas pu être généré.");
       return;
    }
    setLoading(true);
    try {
      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: formData.id,
        document_image: fileData || "",
        mimeType: mimeType || "",
        aux_images: auxImages,
        statut: formData.statut || DocStatus.SUIVRE,
        rappel_actif: (formData.statut !== DocStatus.CLASSER) || !!formData.rappel_details,
        rappel_details: formData.rappel_details || "",
        fait_a: formData.fait_a || "Tahannaout",
        fait_le: formData.fait_le || new Date().toLocaleDateString('fr-FR'),
        created_at: initialData?.created_at && !initialData.id.startsWith("TEMP") ? initialData.created_at : Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!showForm && !analyzing) {
    return (
      <div className="flex flex-col h-full bg-white dark:bg-slate-950 p-6 overflow-y-auto">
        <div className="flex flex-col items-center mb-10 mt-4">
          <ShieldAlert size={56} className="text-brand mb-4" />
          <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Nouvel Avis</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Assistant Administratif Avisapp</p>
        </div>

        <div className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => cameraInputRef.current?.click()} className="flex flex-col items-center justify-center bg-brand text-white p-8 rounded-[2rem] shadow-xl active:scale-95 transition-all">
               <Camera size={32} />
               <span className="text-[10px] font-black mt-3 uppercase tracking-widest">Appareil Photo</span>
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center justify-center bg-blue-600 text-white p-8 rounded-[2rem] shadow-xl active:scale-95 transition-all">
              <Upload size={32} />
              <span className="text-[10px] font-black mt-3 uppercase tracking-widest">Importer PDF/Image</span>
            </button>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Notes ou Description (IA)</label>
            <textarea 
              className="w-full p-5 bg-slate-50 dark:bg-slate-900 rounded-3xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white font-medium"
              placeholder="Décrivez l'incident ici pour aider l'IA..."
              rows={4}
              value={userText}
              onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setUserText(e.target.value)}
            />
          </div>

          {fileData && (
            <div className="flex items-center gap-3 bg-brand/5 dark:bg-brand/10 p-4 rounded-2xl border-2 border-dashed border-brand/20">
              <FileText size={20} className="text-brand" />
              <span className="text-xs font-bold text-slate-600 dark:text-slate-300 truncate flex-1">{mimeType.includes('pdf') ? 'Fichier PDF' : 'Image prête'}</span>
              <button onClick={() => { setFileData(null); setMimeType(""); }} className="bg-red-50 dark:bg-red-900/20 p-1.5 rounded-lg"><X size={16} className="text-red-500" /></button>
            </div>
          )}

          <div className="flex flex-col gap-3 pt-4">
            <button 
              onClick={performAnalysis}
              disabled={!fileData && !userText.trim()}
              className="w-full bg-brand text-white py-5 rounded-3xl font-black text-sm flex items-center justify-center gap-3 shadow-xl disabled:opacity-30 active:scale-95 transition-all"
            >
              <Wand2 size={20} /> ANALYSER AVEC L'IA
            </button>
            <button onClick={() => setShowForm(true)} className="w-full bg-slate-100 dark:bg-slate-900 text-slate-500 py-4 rounded-3xl font-black text-[10px] uppercase tracking-widest">Saisie Manuelle</button>
          </div>
        </div>
        <button onClick={onCancel} className="mt-12 text-slate-400 font-black text-[10px] uppercase tracking-widest text-center">Annuler</button>
        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
      </div>
    );
  }

  if (analyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-6 bg-white dark:bg-slate-950 p-10 text-center">
        <Loader2 size={64} className="text-brand animate-spin" />
        <p className="font-black text-brand uppercase tracking-widest animate-pulse">Analyse IA en cours...</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 relative">
      <div className="flex-1 overflow-y-auto pb-36">
        <div className="p-4 space-y-8">
          <section className="space-y-3">
            <h4 className="text-xs font-black text-brand uppercase tracking-widest border-b-2 border-brand/10">1. AVIS D'INCIDENT</h4>

            <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border-2 border-brand/20 shadow-sm">
              <label className="block text-[9px] font-black text-brand uppercase mb-1 tracking-widest">Numéro d'Avis Officiel</label>
              <input className="w-full bg-transparent font-black text-slate-900 dark:text-white text-base outline-none" value={formData?.id || ""} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormData({...formData, id: e.target.value})} />
            </div>

            <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
              <div className="flex items-center gap-2 mb-1">
                <Tag size={12} className="text-slate-400" />
                <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Nature d'incident</label>
              </div>
              <select 
                className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" 
                value={formData?.nature_incident || IncidentType.AUTRE} 
                onChange={(e) => setFormData({...formData, nature_incident: e.target.value as IncidentType})}
              >
                {Object.values(IncidentType).map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
            </div>

            <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
              <div className="flex items-center gap-2 mb-1">
                <Calendar size={12} className="text-slate-400" />
                <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Date de l'incident (ISO)</label>
              </div>
              <input 
                type="date"
                className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" 
                value={formData?.date_iso || ""} 
                onChange={(e) => setFormData({...formData, date_iso: e.target.value})} 
              />
            </div>

            <Field label="Victime ou objet du sinistre" value={formData?.victime_objet} onChange={(v: string) => setFormData({...formData, victime_objet: v})} />
            <Field label="Description du sinistre" value={formData?.description_sinistre} onChange={(v: string) => setFormData({...formData, description_sinistre: v})} />
            <Field label="Lieu, date et heure du sinistre" value={formData?.lieu_date_heure} onChange={(v: string) => setFormData({...formData, lieu_date_heure: v})} />
            <Field label="Dommages (nature et évaluation)" value={formData?.dommages} onChange={(v: string) => setFormData({...formData, dommages: v})} />

            <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Causes et circonstances</label>
              <textarea className="w-full bg-transparent font-bold outline-none dark:text-white text-xs mb-4" rows={4} value={formData?.causes_circonstances || ""} onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setFormData({...formData, causes_circonstances: e.target.value})} />
              <div className="flex gap-2 overflow-x-auto">
                {auxImages.map((img, i) => (
                  <div key={i} className="relative w-20 h-20 rounded-xl overflow-hidden shrink-0">
                    <img src={img} className="w-full h-full object-cover" />
                    <button onClick={() => setAuxImages(auxImages.filter((_, idx) => idx !== i))} className="absolute top-0 right-0 bg-red-500 text-white p-1 rounded-bl-lg"><X size={12}/></button>
                  </div>
                ))}
                {auxImages.length < 3 && (
                  <button onClick={() => auxInputRef.current?.click()} className="w-20 h-20 rounded-xl border-2 border-dashed border-slate-200 flex items-center justify-center text-slate-300"><Camera size={20}/></button>
                )}
              </div>
              <input type="file" accept="image/*" className="hidden" ref={auxInputRef} onChange={handleAuxImage} />
            </div>

            <Field label="Responsabilités" value={formData?.responsabilites} onChange={(v: string) => setFormData({...formData, responsabilites: v})} />
            <Field label="Mesures prises" value={formData?.mesures_prises} onChange={(v: string) => setFormData({...formData, mesures_prises: v})} />
            <Field label="Références autorites" value={formData?.references_autorites} onChange={(v: string) => setFormData({...formData, references_autorites: v})} />
            <Field label="Observations" value={formData?.observations} onChange={(v: string) => setFormData({...formData, observations: v})} />

            <div className="grid grid-cols-2 gap-4">
               <Field icon={<MapPin size={12}/>} label="Fait à :" value={formData?.fait_a} onChange={(v: string) => setFormData({...formData, fait_a: v})} />
               <Field icon={<Calendar size={12}/>} label="Le :" value={formData?.fait_le} onChange={(v: string) => setFormData({...formData, fait_le: v})} />
            </div>
          </section>

          <section className="space-y-3">
            <h4 className="text-xs font-black text-brand uppercase tracking-widest border-b-2 border-brand/10">2. RAPPORT D'ENQUÊTE</h4>
            <Field label="Introduction" value={formData?.rapport_introduction} isTextarea onChange={(v: string) => setFormData({...formData, rapport_introduction: v})} />
            <Field label="Analyse technique" value={formData?.rapport_analyse_technique} isTextarea onChange={(v: string) => setFormData({...formData, rapport_analyse_technique: v})} />
            <Field label="Analyse des causes" value={formData?.rapport_analyse_causes} isTextarea onChange={(v: string) => setFormData({...formData, rapport_analyse_causes: v})} />
            <Field label="Responsabilités (Rapport)" value={formData?.rapport_responsabilites} isTextarea onChange={(v: string) => setFormData({...formData, rapport_responsabilites: v})} />
            <Field label="Actions correctives" value={formData?.rapport_actions_correctives} isTextarea onChange={(v: string) => setFormData({...formData, rapport_actions_correctives: v})} />
            <Field label="Recommandations" value={formData?.rapport_recommandations} isTextarea onChange={(v: string) => setFormData({...formData, rapport_recommandations: v})} />
            <Field label="Conclusion" value={formData?.rapport_conclusion} isTextarea onChange={(v: string) => setFormData({...formData, rapport_conclusion: v})} />
          </section>

          <section className="space-y-3">
            <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b-2 border-slate-200/50">3. GESTION ET SUIVI</h4>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 shadow-sm">
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-2">Statut</label>
                <select className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" value={formData?.statut} onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setFormData({...formData, statut: e.target.value as DocStatus})}>
                    <option value={DocStatus.SUIVRE}>À SUIVRE</option>
                    <option value={DocStatus.CLASSER}>CLASSER</option>
                </select>
              </div>

              <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 shadow-sm">
                <div className="flex items-center gap-2 mb-1">
                  <Clock size={12} className="text-slate-400" />
                  <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Date de rappel</label>
                </div>
                <input 
                  type="datetime-local"
                  className="w-full bg-transparent font-bold outline-none dark:text-white text-[10px]" 
                  value={formData?.rappel_details?.includes('T') ? formData.rappel_details : ""} 
                  onChange={(e) => setFormData({...formData, rappel_details: e.target.value})} 
                />
              </div>
            </div>
            <Field 
              label="Notes de rappel / Action à suivre" 
              value={formData?.rappel_details && !formData.rappel_details.includes('T') ? formData.rappel_details : ""} 
              onChange={(v: string) => setFormData({...formData, rappel_details: v})} 
            />
          </section>
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-50 dark:from-slate-950 pt-10 flex gap-3 z-30">
        <button onClick={handleSave} disabled={loading} className="flex-1 bg-brand text-white py-5 rounded-[2rem] font-black text-xl shadow-2xl flex items-center justify-center gap-3 active:scale-95 transition-transform">
          {loading ? <Loader2 className="animate-spin" /> : <Save />} ENREGISTRER
        </button>
      </div>
    </div>
  );
};

interface FieldProps {
  label: string;
  value?: string;
  onChange: (val: string) => void;
  isTextarea?: boolean;
  icon?: React.ReactNode;
}

const Field: React.FC<FieldProps> = ({ label, value, onChange, isTextarea, icon }) => (
  <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
    <div className="flex items-center gap-2 mb-1">
      {icon && <span className="text-slate-400">{icon}</span>}
      <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">{label}</label>
    </div>
    {isTextarea ? (
      <textarea className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" rows={3} value={value || ""} onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => onChange(e.target.value)} />
    ) : (
      <input className="w-full bg-transparent font-bold outline-none dark:text-white text-xs" value={value || ""} onChange={(e: React.ChangeEvent<HTMLInputElement>) => onChange(e.target.value)} />
    )}
  </div>
);

export enum DocStatus {
  SUIVRE = "Suivre",
  CLASSER = "Classer"
}

export enum IncidentType {
  INCENDIE = "Incendie",
  DEGAT_EAUX = "Dégât des eaux",
  VANDALISME = "Vandalisme",
  ACCIDENT_TRAVAIL = "Accident de travail",
  PANNE_TECHNIQUE = "Panne technique",
  VOL_EFFRACTION = "Vol / Effraction",
  SINISTRE_ELECTRIQUE = "Sinistre électrique",
  RESEAU_ELECTRIQUE = "Réseau Électrique",
  TIERS = "Tiers",
  AUTRE = "Autre"
}

export interface DocumentData {
  id: string; // Format: SRM-MS/DPH/AI-MMYYN
  document_image: string; 
  mimeType: string;
  aux_images: string[]; // Max 3 images liées aux causes et circonstances

  // Avis d'Incident (Page 1)
  victime_objet: string;
  description_sinistre: string;
  lieu_date_heure: string;
  dommages: string;
  causes_circonstances: string;
  responsabilites: string;
  mesures_prises: string;
  references_autorites: string;
  observations: string;

  // Nouveaux champs signature
  fait_a: string;
  fait_le: string;

  // Rapport d'Enquête (Page 2)
  rapport_introduction: string;
  rapport_analyse_technique: string;
  rapport_analyse_causes: string;
  rapport_responsabilites: string;
  rapport_actions_correctives: string;
  rapport_recommandations: string;
  rapport_conclusion: string;

  // Métadonnées
  date_iso: string; // YYYY-MM-DD
  nature_incident: IncidentType;
  statut: DocStatus;
  rappel_actif: boolean;
  rappel_date?: string; // Date ISO pour le widget
  rappel_details?: string; // Note textuelle
  created_at: number;
}

export type ScreenName = 'scanner' | 'dashboard' | 'stats' | 'settings';

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert, Sparkles, BellRing, MapPin, Calendar, Hash, Tag, Clock } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);

  const [showForm, setShowForm] = useState(!!initialData);

  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || {
    id: "Génération...",
    fait_a: "Tahannaout",
    fait_le: new Date().toISOString().split('T')[0],
    statut: DocStatus.SUIVRE,
    nature_incident: IncidentType.AUTRE,
    date_iso: new Date().toISOString().split('T')[0],
    rappel_details: "",
    rappel_date: ""
  });

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const isNewOrDuplicate = !initialData || !initialData.id || initialData.id === "" || initialData.id.startsWith("TEMP_");
    if (isNewOrDuplicate && showForm) {
      updateAutomaticId();
    }
  }, [formData?.date_iso, showForm]);

  const updateAutomaticId = async () => {
    const dateStr = formData?.date_iso || new Date().toISOString().split('T')[0];
    const nextId = await calculateNextSRMId(dateStr);
    setFormData(prev => prev ? { ...prev, id: nextId } : null);
  };

  const calculateNextSRMId = async (dateIso: string) => {
    try {
      let date = new Date(dateIso);
      if (isNaN(date.getTime())) date = new Date();

      const month = String(date.getMonth() + 1).padStart(2, '0');
      const year = String(date.getFullYear()).slice(-2);
      const mmYY = `${month}${year}`;
      const prefix = `SRM-MS/DPH/AI-${mmYY}`;

      const docs = await getAllDocuments();
      const monthlyDocs = docs.filter(d => d.id && d.id.startsWith(prefix));

      let maxN = 0;
      monthlyDocs.forEach(doc => {
        const nPart = doc.id.substring(prefix.length);
        const n = parseInt(nPart, 10);
        if (!isNaN(n) && n > maxN) maxN = n;
      });

      return `${prefix}${maxN + 1}`;
    } catch (e) {
      console.error("Erreur calcul ID", e);
      return `SRM-MS/DPH/AI-${new Date().getTime()}`;
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const performAnalysis = async () => {
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ 
        ...prev, 
        ...result,
        id: prev?.id && prev.id !== "Génération..." ? prev.id : "Génération...",
        fait_a: prev?.fait_a || "Tahannaout",
        fait_le: result.fait_le || prev?.fait_le || new Date().toISOString().split('T')[0],
        date_iso: result.date_iso || prev?.date_iso
      }));
      setShowForm(true);
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
      setShowForm(true); 
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !formData.id || formData.id === "Génération...") {
       alert("Le numéro d'avis n'a pas pu être généré.");
       return;
    }
    setLoading(true);
    try {
      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: formData.id,
        document_image: fileData || "",
        mimeType: mimeType || "",
        aux_images: auxImages,
        statut: formData.statut || DocStatus.SUIVRE,
        rappel_actif: (formData.statut !== DocStatus.CLASSER) || !!formData.rappel_date || !!formData.rappel_details,
        rappel_date: formData.rappel_date || "",
        rappel_details: formData.rappel_details || "",
        fait_a: formData.fait_a || "Tahannaout",
        fait_le: formData.fait_le || new Date().toISOString().split('T')[0],
        created_at: initialData?.created_at && !initialData.id.startsWith("TEMP") ? initialData.created_at : Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!showForm && !analyzing) {
    return (
      <div className="flex flex-col h-full bg-white dark:bg-slate-950 p-6 overflow-y-auto">
        <div className="flex flex-col items-center mb-10 mt-4">
          <ShieldAlert size={56} className="text-brand mb-4" />
          <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Nouvel Avis</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Assistant Administratif Avisapp</p>
        </div>

        <div className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => cameraInputRef.current?.click()} className="flex flex-col items-center justify-center bg-brand text-white p-8 rounded-[2rem] shadow-xl active:scale-95 transition-all">
               <Camera size={32} />
               <span className="text-[10px] font-black mt-3 uppercase tracking-widest">Appareil Photo</span>
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center justify-center bg-blue-600 text-white p-8 rounded-[2rem] shadow-xl active:scale-95 transition-all">
              <Upload size={32} />
              <span className="text-[10px] font-black mt-3 uppercase tracking-widest">Importer PDF/Image</span>
            </button>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Notes ou Description (IA)</label>
            <textarea 
              className="w-full p-5 bg-slate-50 dark:bg-slate-900 rounded-3xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white font-medium"
              placeholder="Décrivez l'incident ici pour aider l'IA..."
              rows={4}
              value={userText}
              onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setUserText(e.target.value)}
            />
          </div>

          {fileData && (
            <div className="flex items-center gap-3 bg-brand/5 dark:bg-brand/10 p-4 rounded-2xl border-2 border-dashed border-brand/20">
              <FileText size={20} className="text-brand" />
              <span className="text-xs font-bold text-slate-600 dark:text-slate-300 truncate flex-1">{mimeType.includes('pdf') ? 'Fichier PDF' : 'Image prête'}</span>
              <button onClick={() => { setFileData(null); setMimeType(""); }} className="bg-red-50 dark:bg-red-900/20 p-1.5 rounded-lg"><X size={16} className="text-red-500" /></button>
            </div>
          )}

          <div className="flex flex-col gap-3 pt-4">
            <button 
              onClick={performAnalysis}
              disabled={!fileData && !userText.trim()}
