                    <Loader2 size={48} className="animate-spin mb-4 text-[#0ABAB5]" />
                    <p className="font-bold text-xl uppercase tracking-widest text-center px-6">Traitement de l'importation...</p>
                </div>
            )}

            {/* SECTION IA */}
            <div className="bg-[#020617] rounded-[2.5rem] border border-slate-800 p-8 mb-8 shadow-2xl relative overflow-hidden">
                <div className="flex items-center gap-4 mb-8">
                    <div className="bg-slate-900/50 p-3 rounded-2xl border border-slate-800">
                        <Lock className="text-[#0ABAB5]" size={28} />
                    </div>
                    <div>
                        <h3 className="text-xl font-black text-[#0ABAB5] uppercase tracking-tighter leading-none">Configuration</h3>
                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Intelligence Artificielle</p>
                    </div>
                </div>

                <div className={`mb-8 p-6 rounded-3xl border-2 flex items-center justify-between transition-all ${hasApiKey ? 'bg-emerald-500/5 border-emerald-500/20' : 'bg-red-500/5 border-red-500/20'}`}>
                    <div className="flex items-center gap-4">
                        <div className={`p-2 rounded-xl ${hasApiKey ? 'bg-emerald-500/20' : 'bg-red-500/20'}`}>
                            {hasApiKey ? <CheckCircle2 className="text-emerald-500" size={24} /> : <AlertCircle className="text-red-500" size={24} />}
                        </div>
                        <div>
                            <span className={`block text-[10px] font-black uppercase tracking-widest ${hasApiKey ? 'text-emerald-500' : 'text-red-500'}`}>
                                {hasApiKey ? "Service Opérationnel" : "Service Interrompu"}
                            </span>
                            <span className="text-sm font-bold text-white">
                                {hasApiKey ? "Clé API validée" : "Aucune clé configurée"}
                            </span>
                        </div>
                    </div>
                    {hasApiKey && <RefreshCw size={16} className="text-slate-700 animate-spin-slow" />}
                </div>

                <div className="space-y-4">
                    <button 
                        onClick={handleSelectKey}
                        className="w-full bg-[#0ABAB5] hover:bg-[#099994] text-slate-950 py-5 rounded-2xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-3 shadow-[0_10px_30px_rgba(10,186,181,0.2)] active:scale-[0.98] transition-all"
                    >
                        <Key size={18} />
                        {hasApiKey ? "Changer de Clé / Projet" : "Configurer ma clé Gemini"}
                    </button>
                    <p className="text-center">
