            <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 p-8 space-y-6 mb-8">
                <div className="flex items-center space-x-2 text-brand">
                    <Bell size={24} />
