            >
              <Wand2 size={20} /> ANALYSER AVEC L'IA
            </button>
            <button onClick={() => setShowForm(true)} className="w-full bg-slate-100 dark:bg-slate-900 text-slate-500 py-4 rounded-3xl font-black text-[10px] uppercase tracking-widest">Saisie Manuelle</button>
          </div>
