import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, IncidentType } from "../types";

const avisAppSchema = {
  type: Type.OBJECT,
  properties: {
    victime_objet: { type: Type.STRING },
    description_sinistre: { type: Type.STRING },
    lieu_date_heure: { type: Type.STRING },
    dommages: { type: Type.STRING },
    causes_circonstances: { type: Type.STRING },
    responsabilites: { type: Type.STRING },
    mesures_prises: { type: Type.STRING },
    references_autorites: { type: Type.STRING },
    observations: { type: Type.STRING },
    fait_a: { type: Type.STRING },
    fait_le: { type: Type.STRING },

    rapport_introduction: { type: Type.STRING },
    rapport_analyse_technique: { type: Type.STRING },
    rapport_analyse_causes: { type: Type.STRING },
    rapport_responsabilites: { type: Type.STRING },
    rapport_actions_correctives: { type: Type.STRING },
    rapport_recommandations: { type: Type.STRING },
    rapport_conclusion: { type: Type.STRING },

    nature_incident: { type: Type.STRING, enum: Object.values(IncidentType) },
    date_iso: { type: Type.STRING, description: "Date au format YYYY-MM-DD identifiée dans le contenu" }
  },
  required: ["victime_objet", "description_sinistre", "lieu_date_heure", "nature_incident", "date_iso"]
};

const rapportOnlySchema = {
  type: Type.OBJECT,
  properties: {
    rapport_introduction: { type: Type.STRING },
    rapport_analyse_technique: { type: Type.STRING },
    rapport_analyse_causes: { type: Type.STRING },
    rapport_responsabilites: { type: Type.STRING },
    rapport_actions_correctives: { type: Type.STRING },
    rapport_recommandations: { type: Type.STRING },
    rapport_conclusion: { type: Type.STRING }
  },
  required: ["rapport_introduction", "rapport_analyse_technique", "rapport_analyse_causes", "rapport_responsabilites", "rapport_actions_correctives", "rapport_recommandations", "rapport_conclusion"]
};

export const analyzeIncident = async (
  base64Data: string | null,
  mimeType: string | null,
  userNotes: string = ""
): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contents: any = { parts: [] };

  if (base64Data && mimeType) {
    const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;
    contents.parts.push({ inlineData: { mimeType, data: cleanBase64 } });
  }

  const prompt = `
    RÔLE : Tu es un assistant administratif et technique expert en rédaction d'Avis d'Incident et de Rapports d'Enquête.
    TON : Français administratif clair, neutre, structuré et factuel.

    INSTRUCTIONS :
    - Analyse l'image/PDF et les notes : "${userNotes}".
    - Remplis toutes les rubriques du rapport.
    - Pour 'fait_a', utilise 'Tahannaout' par défaut si non trouvé.
    - Pour 'fait_le', utilise la date du jour si non trouvée.
  `;

  contents.parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: avisAppSchema,
        temperature: 0.1,
        systemInstruction: "Tu es l'assistant Avisapp. Rédige de façon administrative stricte. Réponds uniquement en JSON."
      }
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA.");
    return JSON.parse(text);
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

/**
 * Génère spécifiquement le rapport d'enquête à partir des données de l'avis d'incident
 */
export const updateRapportFromAvis = async (avisData: Partial<DocumentData>): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Basé sur l'Avis d'Incident suivant, rédige un Rapport d'Enquête structuré et professionnel.

    DONNÉES DE L'AVIS :
    - Victime/Objet : ${avisData.victime_objet}
    - Description : ${avisData.description_sinistre}
    - Lieu/Date/Heure : ${avisData.lieu_date_heure}
    - Dommages : ${avisData.dommages}
    - Causes/Circonstances : ${avisData.causes_circonstances}
    - Responsabilités : ${avisData.responsabilites}
    - Mesures prises : ${avisData.mesures_prises}
    - Observations : ${avisData.observations}

    INSTRUCTIONS :
    Développe chaque section du rapport (Introduction, Analyse technique, Analyse des causes, Responsabilités, Actions correctives, Recommandations, Conclusion) en utilisant un langage administratif et technique soutenu.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: rapportOnlySchema,
        temperature: 0.2,
        systemInstruction: "Tu es un expert en sécurité et gestion des risques. Ton rapport doit être détaillé et formel. Réponds uniquement en JSON."
      }
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA.");
    return JSON.parse(text);
  } catch (error: any) {
    console.error("Gemini Rapport Update Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert, Sparkles, BellRing, MapPin, Calendar, Hash, Tag, Clock, CalendarDays, Timer, Zap } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident, updateRapportFromAvis } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [updatingRapport, setUpdatingRapport] = useState(false);

  const [showForm, setShowForm] = useState(!!initialData);

  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || {
    id: "Génération...",
    fait_a: "Tahannaout",
    fait_le: new Date().toISOString().split('T')[0],
    statut: DocStatus.SUIVRE,
    nature_incident: IncidentType.AUTRE,
    date_iso: new Date().toISOString().split('T')[0],
    rappel_details: "",
    rappel_date: ""
  });

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const isNewOrDuplicate = !initialData || !initialData.id || initialData.id === "" || initialData.id.startsWith("TEMP_");
    if (isNewOrDuplicate && showForm) {
      updateAutomaticId();
    }
  }, [formData?.date_iso, showForm]);

  const updateAutomaticId = async () => {
    const dateStr = formData?.date_iso || new Date().toISOString().split('T')[0];
    const nextId = await calculateNextSRMId(dateStr);
    setFormData(prev => prev ? { ...prev, id: nextId } : null);
  };

  const calculateNextSRMId = async (dateIso: string) => {
    try {
      let date = new Date(dateIso);
      if (isNaN(date.getTime())) date = new Date();

      const month = String(date.getMonth() + 1).padStart(2, '0');
      const year = String(date.getFullYear()).slice(-2);
      const mmYY = `${month}${year}`;
      const prefix = `SRM-MS/DPH/AI-${mmYY}`;

      const docs = await getAllDocuments();
      const monthlyDocs = docs.filter(d => d.id && d.id.startsWith(prefix));

      let maxN = 0;
      monthlyDocs.forEach(doc => {
        const nPart = doc.id.substring(prefix.length);
        const n = parseInt(nPart, 10);
        if (!isNaN(n) && n > maxN) maxN = n;
      });

      return `${prefix}${maxN + 1}`;
    } catch (e) {
      console.error("Erreur calcul ID", e);
      return `SRM-MS/DPH/AI-${new Date().getTime()}`;
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  const performAnalysis = async () => {
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ 
        ...prev, 
        ...result,
        id: prev?.id && prev.id !== "Génération..." ? prev.id : "Génération...",
        fait_a: prev?.fait_a || "Tahannaout",
        fait_le: result.fait_le || prev?.fait_le || new Date().toISOString().split('T')[0],
        date_iso: result.date_iso || prev?.date_iso || new Date().toISOString().split('T')[0]
      }));
      setShowForm(true);
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
      setShowForm(true); 
    } finally {
      setAnalyzing(false);
    }
  };

  const handleRapportIAUpdate = async () => {
    if (!formData) return;
    setUpdatingRapport(true);
    try {
      const rapportUpdates = await updateRapportFromAvis(formData);
      setFormData(prev => ({ ...prev, ...rapportUpdates }));
    } catch (err: any) {
      alert(`Erreur IA Rapport : ${err?.message}`);
    } finally {
      setUpdatingRapport(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !formData.id || formData.id === "Génération...") {
       alert("Le numéro d'avis n'a pas pu être généré.");
       return;
    }
    setLoading(true);
    try {
      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: formData.id,
        document_image: fileData || "",
        mimeType: mimeType || "",
        aux_images: auxImages,
        statut: formData.statut || DocStatus.SUIVRE,
        rappel_actif: (formData.statut !== DocStatus.CLASSER) || !!formData.rappel_date || !!formData.rappel_details,
        rappel_date: formData.rappel_date || "",
        rappel_details: formData.rappel_details || "",
        fait_a: formData.fait_a || "Tahannaout",
        fait_le: formData.fait_le || new Date().toISOString().split('T')[0],
        created_at: initialData?.created_at && !initialData.id.startsWith("TEMP") ? initialData.created_at : Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
