import { GoogleGenAI, Type } from "@google/genai";
import { DocumentData, IncidentType } from "../types";

const avisAppSchema = {
  type: Type.OBJECT,
  properties: {
    victime_objet: { type: Type.STRING },
    description_sinistre: { type: Type.STRING },
    lieu_date_heure: { type: Type.STRING },
    dommages: { type: Type.STRING },
    causes_circonstances: { type: Type.STRING },
    responsabilites: { type: Type.STRING },
    mesures_prises: { type: Type.STRING },
    references_autorites: { type: Type.STRING },
    observations: { type: Type.STRING },
    fait_a: { type: Type.STRING },
    fait_le: { type: Type.STRING },

    nature_incident: { type: Type.STRING, enum: Object.values(IncidentType) },
    date_iso: { type: Type.STRING, description: "Date au format YYYY-MM-DD" }
  },
  required: ["victime_objet", "description_sinistre", "lieu_date_heure", "nature_incident", "date_iso"]
};

const rapportOnlySchema = {
  type: Type.OBJECT,
  properties: {
    rapport_introduction: { type: Type.STRING },
    rapport_analyse_technique: { type: Type.STRING },
    rapport_analyse_causes: { type: Type.STRING },
    rapport_responsabilites: { type: Type.STRING },
    rapport_actions_correctives: { type: Type.STRING },
    rapport_recommandations: { type: Type.STRING },
    rapport_conclusion: { type: Type.STRING }
  },
  required: ["rapport_introduction", "rapport_analyse_technique", "rapport_analyse_causes", "rapport_responsabilites", "rapport_actions_correctives", "rapport_recommandations", "rapport_conclusion"]
};

export const analyzeIncident = async (
  base64Data: string | null,
  mimeType: string | null,
  userNotes: string = ""
): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const contents: any = { parts: [] };

  if (base64Data && mimeType) {
    const cleanBase64 = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;
    contents.parts.push({ inlineData: { mimeType, data: cleanBase64 } });
  }

  const prompt = `
    RÔLE : Assistant expert en rédaction d'Avis d'Incident.
    INSTRUCTIONS :
    - Analyse la source (image/PDF) et les notes : "${userNotes}".
    - Extrais et structure les informations pour un rapport officiel.
    - Pour 'fait_a', utilise 'Tahannaout' par défaut.
    - Pour 'fait_le' et 'date_iso', utilise la date du jour (${new Date().toISOString().split('T')[0]}) si aucune date n'est détectée.
  `;

  contents.parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: avisAppSchema,
        temperature: 0.1
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Analyze Error:", error);
    throw error;
  }
};

/**
 * Réviser uniquement les champs textuels fournis dans le formulaire.
 * Objectif : Correction orthographique, grammaticale et style administratif.
 */
export const reviseAvisFields = async (currentAvis: Partial<DocumentData>): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    RÔLE : Correcteur et rédacteur administratif expert.
    MISSION : Réviser les champs textuels d'un Avis d'Incident.

    INSTRUCTIONS :
    1. Corrige uniquement l'orthographe et la grammaire.
    2. Reformule les phrases pour un style administratif professionnel, clair et concis (Français soutenu).
    3. NE CHANGE PAS les faits ni les informations de base.
    4. Ignore toute source de données externe (images/PDF), base-toi uniquement sur le texte ci-dessous.
    5. Conserve la valeur 'date_iso' et les autres champs techniques tels quels.

    TEXTE À RÉVISER :
    - Victime/Objet : ${currentAvis.victime_objet}
    - Description : ${currentAvis.description_sinistre}
    - Lieu/Date/Heure : ${currentAvis.lieu_date_heure}
    - Dommages : ${currentAvis.dommages}
    - Causes/Circonstances : ${currentAvis.causes_circonstances}
    - Responsabilités : ${currentAvis.responsabilites}
    - Mesures prises : ${currentAvis.mesures_prises}
    - Observations : ${currentAvis.observations}
    - Fait à : ${currentAvis.fait_a}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: avisAppSchema,
        temperature: 0.1
      }
    });
    const result = JSON.parse(response.text || "{}");

    // On s'assure de ne pas écraser les champs non textuels ou techniques s'ils manquent
    return {
      ...currentAvis,
      ...result
    };
  } catch (error) {
    console.error("Gemini Revision Error:", error);
    throw error;
  }
};

export const updateRapportFromAvis = async (avisData: Partial<DocumentData>): Promise<Partial<DocumentData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Rédige un Rapport d'Enquête structuré et complet basé exclusivement sur les données de cet Avis d'Incident :
    ${JSON.stringify(avisData, null, 2)}

    Développe chaque section technique de manière professionnelle et détaillée.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: rapportOnlySchema,
        temperature: 0.2
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Rapport Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Loader2, Save, RefreshCw, Wand2, Paperclip, X, FileText, ShieldAlert, Sparkles, BellRing, MapPin, Calendar, Hash, Tag, Clock, CalendarDays, Timer, Zap } from 'lucide-react';
import { DocumentData, DocStatus, IncidentType } from '../types';
import { analyzeIncident, updateRapportFromAvis, reviseAvisFields } from '../services/geminiService';
import { saveDocument, getAllDocuments } from '../services/db';

interface ScannerProps {
  onSave: () => void;
  onCancel: () => void;
  initialData?: DocumentData | null;
}

export const Scanner: React.FC<ScannerProps> = ({ onSave, onCancel, initialData }) => {
  const [fileData, setFileData] = useState<string | null>(initialData?.document_image || null);
  const [mimeType, setMimeType] = useState<string>(initialData?.mimeType || "image/jpeg");
  const [auxImages, setAuxImages] = useState<string[]>(initialData?.aux_images || []);
  const [userText, setUserText] = useState("");
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [revisingAvis, setRevisingAvis] = useState(false);
  const [updatingRapport, setUpdatingRapport] = useState(false);

  const [showForm, setShowForm] = useState(!!initialData);

  const todayStr = new Date().toISOString().split('T')[0];

  const [formData, setFormData] = useState<Partial<DocumentData> | null>(initialData || {
    id: "Génération...",
    fait_a: "Tahannaout",
    fait_le: todayStr,
    statut: DocStatus.SUIVRE,
    nature_incident: IncidentType.AUTRE,
    date_iso: todayStr,
    rappel_details: "",
    rappel_date: ""
  });

  const cameraInputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const auxInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const isNewOrDuplicate = !initialData || !initialData.id || initialData.id === "" || initialData.id.startsWith("TEMP_");
    if (isNewOrDuplicate && showForm) {
      updateAutomaticId();
    }
  }, [formData?.date_iso, showForm]);

  const updateAutomaticId = async () => {
    const dateStr = formData?.date_iso || todayStr;
    const nextId = await calculateNextSRMId(dateStr);
    setFormData(prev => prev ? { ...prev, id: nextId } : null);
  };

  const calculateNextSRMId = async (dateIso: string) => {
    try {
      let date = new Date(dateIso);
      if (isNaN(date.getTime())) date = new Date();

      const month = String(date.getMonth() + 1).padStart(2, '0');
      const year = String(date.getFullYear()).slice(-2);
      const mmYY = `${month}${year}`;
      const prefix = `SRM-MS/DPH/AI-${mmYY}`;

      const docs = await getAllDocuments();
      const monthlyDocs = docs.filter(d => d.id && d.id.startsWith(prefix));

      let maxN = 0;
      monthlyDocs.forEach(doc => {
        const nPart = doc.id.substring(prefix.length);
        const n = parseInt(nPart, 10);
        if (!isNaN(n) && n > maxN) maxN = n;
      });

      return `${prefix}${maxN + 1}`;
    } catch (e) {
      return `SRM-MS/DPH/AI-${new Date().getTime()}`;
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMimeType(file.type);
      const reader = new FileReader();
      reader.onloadend = () => setFileData(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAuxImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && auxImages.length < 3) {
      const reader = new FileReader();
      reader.onloadend = () => setAuxImages([...auxImages, reader.result as string]);
      reader.readAsDataURL(file);
    }
  };

  /**
   * Analyse initiale à partir de l'image/PDF et des notes utilisateur
   */
  const performInitialAnalysis = async () => {
    setAnalyzing(true);
    try {
      const result = await analyzeIncident(fileData, mimeType, userText);
      setFormData(prev => ({ 
        ...prev, 
        ...result,
        id: prev?.id && prev.id !== "Génération..." ? prev.id : "Génération...",
        fait_a: result.fait_a || prev?.fait_a || "Tahannaout",
        fait_le: result.fait_le || prev?.fait_le || todayStr,
        date_iso: result.date_iso || prev?.date_iso || todayStr
      }));
      setShowForm(true);
    } catch (err: any) {
      alert(`Erreur IA : ${err?.message}`);
      setShowForm(true); 
    } finally {
      setAnalyzing(false);
    }
  };

  /**
   * Révision intelligente : Correction orthographique et reformulation administrative.
   * Ne touche qu'aux champs textuels saisis.
   */
  const handleAvisRevisionIA = async () => {
    if (!formData) return;
    setRevisingAvis(true);
    try {
      const revisedData = await reviseAvisFields(formData);
      setFormData(prev => ({ 
        ...prev, 
        ...revisedData,
        // On s'assure de garder les champs techniques
        id: prev?.id,
        date_iso: prev?.date_iso,
        fait_le: prev?.fait_le,
        nature_incident: prev?.nature_incident
      }));
    } catch (err: any) {
      alert(`Erreur de révision : ${err?.message}`);
    } finally {
      setRevisingAvis(false);
    }
  };

  const handleRapportIAUpdate = async () => {
    if (!formData) return;
    setUpdatingRapport(true);
    try {
      const rapportUpdates = await updateRapportFromAvis(formData);
      setFormData(prev => ({ ...prev, ...rapportUpdates }));
    } catch (err: any) {
      alert(`Erreur IA Rapport : ${err?.message}`);
    } finally {
      setUpdatingRapport(false);
    }
  };

  const handleSave = async () => {
    if (!formData || !formData.id || formData.id === "Génération...") {
       alert("Le numéro d'avis n'a pas pu être généré.");
       return;
    }
    setLoading(true);
    try {
      const finalDoc: DocumentData = {
        ...(formData as DocumentData),
        id: formData.id,
        document_image: fileData || "",
        mimeType: mimeType || "",
        aux_images: auxImages,
        statut: formData.statut || DocStatus.SUIVRE,
        rappel_actif: (formData.statut !== DocStatus.CLASSER) || !!formData.rappel_date || !!formData.rappel_details,
        rappel_date: formData.rappel_date || "",
        rappel_details: formData.rappel_details || "",
        fait_a: formData.fait_a || "Tahannaout",
        fait_le: formData.fait_le || todayStr,
        created_at: initialData?.created_at && !initialData.id.startsWith("TEMP") ? initialData.created_at : Date.now()
      };

      await saveDocument(finalDoc);
      onSave();
    } catch (e) {
      alert("Erreur de sauvegarde.");
    } finally {
      setLoading(false);
    }
  };

  if (!showForm && !analyzing) {
    return (
      <div className="flex flex-col h-full bg-white dark:bg-slate-950 p-5 overflow-y-auto">
        <div className="flex items-center gap-3 mb-6 mt-1">
          <ShieldAlert size={32} className="text-brand shrink-0" />
          <h2 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Nouvel Avis</h2>
        </div>

        <div className="flex flex-col flex-1 gap-4">
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => cameraInputRef.current?.click()} className="flex flex-col items-center justify-center bg-brand text-white p-5 rounded-[1.5rem] shadow-lg active:scale-95 transition-all">
               <Camera size={24} />
               <span className="text-[9px] font-black mt-2 uppercase tracking-widest">Appareil Photo</span>
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center justify-center bg-blue-600 text-white p-5 rounded-[1.5rem] shadow-lg active:scale-95 transition-all">
              <Upload size={24} />
              <span className="text-[9px] font-black mt-2 uppercase tracking-widest">Importer</span>
            </button>
          </div>

          <div className="flex flex-col gap-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Notes ou Description (IA)</label>
            <textarea 
              className="w-full p-4 bg-slate-50 dark:bg-slate-900 rounded-2xl text-sm border-2 border-transparent focus:border-brand outline-none transition-all dark:text-white font-medium"
              placeholder="Décrivez l'incident pour l'IA..."
              rows={3}
              value={userText}
              onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => setUserText(e.target.value)}
            />
          </div>

          {fileData && (
            <div className="flex items-center gap-3 bg-brand/5 dark:bg-brand/10 p-3 rounded-xl border-2 border-dashed border-brand/20">
              <FileText size={18} className="text-brand" />
              <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300 truncate flex-1">{mimeType.includes('pdf') ? 'Fichier PDF' : 'Image prête'}</span>
              <button onClick={() => { setFileData(null); setMimeType(""); }} className="bg-red-50 dark:bg-red-900/20 p-1 rounded-lg"><X size={14} className="text-red-500" /></button>
            </div>
          )}

          <div className="flex flex-col gap-2 mt-auto">
            <button 
              onClick={performInitialAnalysis}
              disabled={!fileData && !userText.trim()}
              className="w-full bg-brand text-white py-4 rounded-2xl font-black text-xs flex items-center justify-center gap-3 shadow-xl disabled:opacity-30 active:scale-95 transition-all"
            >
              <Wand2 size={18} /> ANALYSER AVEC L'IA
            </button>
            <button onClick={() => setShowForm(true)} className="w-full bg-slate-100 dark:bg-slate-900 text-slate-500 py-3 rounded-2xl font-black text-[9px] uppercase tracking-widest">Saisie Manuelle</button>
          </div>
        </div>
        <button onClick={onCancel} className="mt-4 text-slate-400 font-black text-[9px] uppercase tracking-widest text-center">Annuler</button>
        <input type="file" accept="image/*" capture="environment" className="hidden" ref={cameraInputRef} onChange={handleFileChange} />
        <input type="file" accept="image/*,application/pdf" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
      </div>
    );
  }

  if (analyzing) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-6 bg-white dark:bg-slate-950 p-10 text-center">
        <Loader2 size={64} className="text-brand animate-spin" />
        <p className="font-black text-brand uppercase tracking-widest animate-pulse">Analyse IA en cours...</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 relative">
      <div className="flex-1 overflow-y-auto pb-36">
        <div className="p-4 space-y-8">
          {/* SECTION 1 - AVIS D'INCIDENT */}
          <section className="space-y-4">
            <div className="flex items-center justify-between border-b-2 border-brand/10 pb-1">
              <h4 className="text-xs font-black text-brand uppercase tracking-widest">1. AVIS D'INCIDENT</h4>
              <button 
                onClick={handleAvisRevisionIA}
                disabled={revisingAvis}
                className="p-1.5 bg-brand/10 text-brand rounded-lg hover:bg-brand/20 transition-all flex items-center gap-1.5 px-2 disabled:opacity-50"
                title="Corriger et reformuler professionnellement les champs actuels"
              >
                {revisingAvis ? <Loader2 size={14} className="animate-spin" /> : <Zap size={14} fill="currentColor"/>}
                <span className="text-[9px] font-black uppercase">{revisingAvis ? "Révision..." : "Réviser"}</span>
              </button>
            </div>

            <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border-2 border-brand/20 shadow-sm">
              <label className="block text-[9px] font-black text-brand uppercase mb-1 tracking-widest">Numéro d'Avis Officiel</label>
              <input className="w-full bg-transparent font-black text-slate-900 dark:text-white text-base outline-none" value={formData?.id || ""} onChange={(e) => setFormData({...formData, id: e.target.value})} />
            </div>

            <div className="bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm relative overflow-hidden group">
              <div className="flex items-center gap-2 mb-1">
                <Tag size={12} className="text-brand" />
                <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Nature d'incident</label>
              </div>
              <select 
                className="w-full bg-transparent font-black outline-none dark:text-white text-sm appearance-none relative z-10" 
                value={formData?.nature_incident || IncidentType.AUTRE} 
                onChange={(e) => setFormData({...formData, nature_incident: e.target.value as IncidentType})}
              >
                {Object.values(IncidentType).map(type => (
                  <option key={type} value={type} className="dark:bg-slate-900">{type}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none">▼</div>
            </div>

            <div className="bg-gradient-to-br from-blue-500/10 to-indigo-500/10 dark:from-blue-900/20 dark:to-indigo-900/20 p-5 rounded-[2rem] border border-blue-200 dark:border-blue-800 shadow-inner">
